const SOC10T2_UNITS=[
 {id:"t2u1",n:1,title:"Society Is Built by People",mins:180,icon:"Target",
  summary:"Culture, norms, values and customs: the invisible building blocks that societies construct \u2014 and that construct us back.",
  keyWords:["social construction","culture","norms","values","customs"],
  sections:[
   {art:"society",h:"Social construction: the big idea",p:[
    "Much of what feels \u2018natural\u2019 in life was actually built by people over time \u2014 sociologists call this social construction. Money, manners, childhood, even what counts as polite: societies made these, and different societies made them differently.",
    "This matters because if something was constructed, it can change, and it can be compared. Sociology studies how these constructions shape our identity \u2014 how we see ourselves and how others see us."],
    ex:{t:"Example — constructed, not natural",b:["A handshake feels like the natural greeting \u2014 until you visit a society that bows instead.","Neither is \u2018correct by nature\u2019; each was built by its society.","That is social construction in one gesture."]}},
   {art:"culture",h:"Culture and customs",p:[
    "Culture is a society\u2019s whole way of life: its beliefs, language, food, dress and traditions. You are soaked in your culture from birth \u2014 it feels like water to a fish.",
    "Customs are traditional practices passed down through generations, such as wedding ceremonies, festivals and naming ceremonies. Customs keep culture alive by repeating it."],
    ex:{t:"Example — culture in a wedding",b:["Compare weddings across cultures: different clothes, foods, music and rituals.","Each version teaches the young what their society values \u2014 family, faith, generosity.","One event, a whole culture on display."]}},
   {art:"control",h:"Norms: the rules of the situation",p:[
    "Norms are the expected behaviours in specific situations \u2014 queueing at the shop, shaking hands when meeting someone, raising your hand in class. Break a norm and people react, even without any law involved.",
    "Norms change with the setting: shouting is normal at a football match and shocking in a library. Learning to read the setting is learning the norms."],
    ex:{t:"Example — same act, different norm",b:["Wearing pyjamas: normal at home, deviant at a formal event.","Nothing about the pyjamas changed \u2014 the situation\u2019s norms did.","Norms belong to situations, not just to people."]}},
   {art:"target",h:"Values: what a society treasures",p:[
    "Values are beliefs about what is important or desirable \u2014 honesty, equality, respect for elders, hard work. Values sit underneath norms: we queue (norm) because we value fairness (value).",
    "Values influence big decisions. A person who deeply values education will prioritise studying; a society that values equality will write it into laws."],
    ex:{t:"Example — value driving behaviour",b:["Two students get the same homework.","One values education highly and studies at once; the other values leisure and delays.","Same task, different values, different behaviour."]}},
  ],
  activity:"List three norms in your school, and for each one, name the value hiding underneath it (for example: uniform \u2192 equality; punctuality \u2192 respect for others' time).",
  check:[
   {q:"The idea that societies build things like manners and money over time is called\u2026",o:["Sampling","Social construction","Meritocracy","Photosynthesis"],a:1},
   {q:"Expected behaviours in specific situations are\u2026",o:["Values","Statistics","Customs","Norms"],a:3},
   {q:"Beliefs about what is important, like honesty or equality, are\u2026",o:["Norms","Roles","Charts","Values"],a:3},
  ]},

 {id:"t2u2",n:2,title:"Roles, Status & Stereotypes",mins:180,icon:"Users",
  summary:"The positions we hold, the scripts attached to them, and the lazy labels that stick to whole groups.",
  keyWords:["role","status","achieved status","ascribed status","stereotype"],
  sections:[
   {art:"roles",h:"Roles: the scripts we play",p:[
    "A role is the expected behaviour tied to a social position. As a student you follow one script (listen, learn, hand in work); as an older sibling at home, another; as a team captain, a third.",
    "One person plays many roles in a single day \u2014 and sometimes roles clash, like when a part-time job (worker role) collides with exam revision (student role)."],
    ex:{t:"Example — role switching",b:["At 8 a.m. Chidi is a student (quiet, note-taking).","At 4 p.m. he is a big brother (protective, in charge).","Same person, different roles, different behaviour \u2014 all day long."]}},
   {art:"layers",h:"Status: your position in society",p:[
    "Status is a person\u2019s position in society. Achieved status is earned by your own actions \u2014 becoming a doctor, a prefect, a champion. Ascribed status is assigned at birth \u2014 your age group, your family, often your ethnicity.",
    "Modern societies claim to reward achieved status, but ascribed status still opens or closes many doors, which is why sociologists keep measuring it."],
    ex:{t:"Example — two kinds of status",b:["A person born into a royal family holds ascribed status \u2014 no exam required.","A surgeon holds achieved status \u2014 years of study earned it.","One was given; one was built."]}},
   {art:"identity",h:"Stereotypes: labels for whole groups",p:[
    "A stereotype is a generalised belief about a whole group \u2014 \u2018all teenagers are rebellious\u2019, \u2018boys are troublemakers\u2019. Stereotypes are quick, lazy and often wrong, yet they shape how people are treated.",
    "Stereotypes matter to identity because being constantly treated as a label can push people toward or away from it \u2014 an idea this course returns to as the self-fulfilling prophecy."],
    ex:{t:"Example — a stereotype at work",b:["A shopkeeper watches teenagers closely, expecting trouble.","The teenagers feel accused and stop shopping there.","The stereotype changed behaviour on BOTH sides \u2014 without a word spoken."]}},
   {art:"identity",h:"How these concepts shape identity",p:[
    "Norms guide your daily actions; roles script your behaviour in each setting; values steer your decisions; status positions you; stereotypes label you. Together they build your social identity \u2014 who you are in society\u2019s eyes and your own.",
    "A person born into a wealthy family, for instance, is ascribed a status and expected to act in ways that match it \u2014 dressing formally, attending certain schools. Identity is never built alone."],
    ex:{t:"Example — the pieces together",b:["Ama: student (role), Grade 10 (ascribed age status), prefect (achieved status), values fairness, faces the \u2018quiet girl\u2019 stereotype.","Every piece shapes how she acts and how others treat her.","That whole package is her social identity."]}},
  ],
  activity:"Map your own identity like Ama's: write two roles you play, one ascribed status, one achieved status, one value you hold, and one stereotype you have faced or seen.",
  check:[
   {q:"A social position earned through your own actions is\u2026",o:["A custom","Ascribed status","Achieved status","A stereotype"],a:2},
   {q:"'All teenagers are rebellious' is an example of\u2026",o:["A value","An achieved status","A stereotype","A pilot study"],a:2},
   {q:"The expected behaviour tied to a position like 'student' or 'parent' is a\u2026",o:["Norm-free zone","Statistic","Role","Sample"],a:2},
  ]},

 {id:"t2u3",n:3,title:"Nature, Nurture & Socialisation",mins:180,icon:"Lightbulb",
  summary:"Are we born or made? The nature\u2013nurture debate, the relativity of culture, and socialisation \u2014 how society gets inside us.",
  keyWords:["nature\u2013nurture debate","relativity of culture","socialisation"],
  sections:[
   {art:"science",h:"The nature\u2013nurture debate",p:[
    "How much of you comes from biology (nature) and how much from society (nurture)? That is the nature\u2013nurture debate. Your genes set some limits \u2014 but sociologists show how powerfully nurture shapes behaviour, taste and ambition.",
    "The strongest evidence for nurture: children raised in different cultures grow up with different languages, manners, beliefs and goals \u2014 differences genes cannot explain."],
    ex:{t:"Example — nurture's power",b:["Identical twins separated at birth into different cultures would speak different languages and follow different customs.","Same genes, different societies, different people.","Nurture writes a huge part of the story."]}},
   {art:"culture",h:"The relativity of culture",p:[
    "Cultures build identity differently \u2014 this is the relativity of culture. Western cultures often prize individualism (personal achievement, standing out); many Eastern cultures prize collectivism (family loyalty, fitting in).",
    "Neither is \u2018right\u2019. But a child raised in each will value different things, chase different goals and even describe themselves differently."],
    ex:{t:"Example — two childhoods",b:["A child in a collectivist culture learns that family loyalty comes first.","A child in an individualist culture learns to celebrate personal achievement.","Each grows an identity tuned to their culture\u2019s settings."]}},
   {art:"social",h:"Socialisation: society getting inside us",p:[
    "Socialisation is the lifelong process of learning your society\u2019s norms, values and roles. It is how culture is passed from one generation to the next \u2014 and how a baby becomes a member of society.",
    "It happens through agents \u2014 family, school, friends, media, religion, workplace \u2014 each teaching different lessons at different life stages. The next unit tours them all."],
    ex:{t:"Example — socialisation in action",b:["Nobody is born knowing to say \u2018thank you\u2019.","Parents model it, praise it, and remind: socialisation at work.","Years later the habit feels natural \u2014 society got inside."]}},
   {art:"social",h:"Norms and values: the foundation",p:[
    "Everything socialisation teaches rests on norms and values \u2014 the behaviours expected of us and the beliefs behind them. They are the foundation of identity: change them and the person\u2019s behaviour changes too.",
    "This is why sociologists study socialisation so closely: whoever teaches the norms and values shapes the next generation\u2019s identity."],
    ex:{t:"Example — foundation shifting",b:["A family that deeply values education raises a child who treats homework as serious.","A peer group that mocks effort can weaken that value in the teenage years.","Identity shifts as the taught norms and values shift."]}},
  ],
  activity:"Write down two things about yourself that are mostly nature (biology) and four that are mostly nurture (taught by family, school, friends or media). Which list was easier to fill?",
  check:[
   {q:"The debate about whether biology or society shapes us more is the\u2026",o:["Nature\u2013nurture debate","Correlation debate","Open\u2013closed debate","Consensus\u2013conflict debate"],a:0},
   {q:"Learning society's norms, values and roles is called\u2026",o:["Urbanisation","Stratification","Triangulation","Socialisation"],a:3},
   {q:"Individualist and collectivist cultures raising different identities shows\u2026",o:["The Hawthorne effect","That customs never differ","The relativity of culture","That genes decide everything"],a:2},
  ]},

 {id:"t2u4",n:4,title:"The Agencies of Socialisation",mins:180,icon:"BookOpen",
  summary:"Family, education, peers, media, religion and workplace: the six great teachers of identity, and how well each one works.",
  keyWords:["primary socialisation","secondary socialisation","agency","peer group"],
  sections:[
   {art:"family",h:"Primary socialisation: the family",p:[
    "Primary socialisation is the first learning of norms, values and behaviour, mainly in the family during early childhood. Language, manners, right-and-wrong: the family lays the base of identity.",
    "Its effect is powerful and long-lasting \u2014 though it varies with parenting styles and family structure. What the family builds, later agencies build ON."],
    ex:{t:"Example — the family's lessons",b:["A toddler learns their native language, learns to share, learns respect for elders \u2014 all at home.","No school taught these first lessons.","That is primary socialisation."]}},
   {art:"school",h:"Secondary socialisation: school and peers",p:[
    "Secondary socialisation continues the learning outside the family. Education teaches skills through the official curriculum \u2014 and quietly teaches punctuality, discipline and respect for authority through the hidden curriculum.",
    "The peer group \u2014 friends and classmates \u2014 shapes trends, language and choices through peer pressure. Peers can reinforce society\u2019s norms or pull against them."],
    ex:{t:"Example — two classrooms of learning",b:["Officially, the lesson is mathematics.","Unofficially, students learn to arrive on time, wait their turn and obey the bell \u2014 the hidden curriculum.","Meanwhile at break, friends teach the newest slang: peers at work."]}},
   {art:"global",h:"Media, religion and the workplace",p:[
    "Media (TV, films, social media) shapes ideas about beauty, success and behaviour through its representations \u2014 powerfully, though it can spread stereotypes and unrealistic ideals.",
    "Religion teaches morals and identity through its teachings \u2014 compassion, honesty, community \u2014 strongest for active believers. The workplace socialises adults through training and professional norms: teamwork, punctuality, dress codes."],
    ex:{t:"Example — three teachers of adulthood",b:["A new nurse learns compassion partly from faith, professionalism from workplace training, and \u2018what success looks like\u2019 partly from media.","Socialisation never stops \u2014 the teachers just change.","Identity keeps being built across the whole of life."]}},
   {art:"agency",h:"How effective is each agency?",p:[
    "Effectiveness varies. Family is strongest early and lingers for life. Education is highly influential but depends on school quality. Peers surge in the teenage years. Media\u2019s reach is enormous; religion depends on belief; the workplace matters most in adulthood.",
    "Exam tip: never just list the agencies \u2014 compare their effectiveness and say WHEN in life each one dominates."],
    ex:{t:"Example — a life in agencies",b:["Ages 0\u20135: family dominates. Ages 5\u201313: school joins in. Teens: peers and media surge.","Adulthood: workplace takes over daily socialisation; religion runs throughout for believers.","One person, six teachers, in shifting order."]}},
  ],
  activity:"Draw a timeline of your life so far. Mark which agency of socialisation was strongest at each stage, and one specific lesson each agency taught you.",
  check:[
   {q:"Primary socialisation happens mainly in the\u2026",o:["Government","Workplace","Family during early childhood","Media only"],a:2},
   {q:"Punctuality and discipline learned quietly at school come from the\u2026",o:["Pilot study","Hidden curriculum","Official curriculum","Sampling frame"],a:1},
   {q:"Which agency usually surges strongest in the teenage years?",o:["The census","The workplace","The courts","The peer group"],a:3},
  ]},

 {id:"t2u5",n:5,title:"How Agencies Shape Us \u2014 and What Theories Say",mins:180,icon:"Sparkles",
  summary:"The processes agencies use (canalisation, role models, peer pressure) and the big theoretical argument about what socialisation is FOR.",
  keyWords:["canalisation","role modelling","consensus","conflict","value consensus","gender role socialisation"],
  sections:[
   {art:"agency",h:"The processes agencies use",p:[
    "Agencies do not just talk \u2014 they use processes. Canalisation channels children toward \u2018appropriate\u2019 interests (girls handed dolls, boys handed toy cars). Role modelling teaches by example: children imitate parents, teachers and stars.",
    "Add the hidden curriculum (school\u2019s unspoken lessons), media representations (images of success and beauty), peer pressure (conform or be left out), religious teachings and workplace training \u2014 and you have the full toolkit that builds identity."],
    ex:{t:"Example — canalisation in a toy shop",b:["One aisle glows pink with dolls and kitchens; another roars with cars and action figures.","Children are steered \u2014 canalised \u2014 toward \u2018their\u2019 aisle before they can spell \u2018gender\u2019.","Interests that look natural were quietly channelled."]}},
   {art:"society",h:"The consensus view: functionalism",p:[
    "Functionalists like Durkheim argue socialisation exists to create social cohesion and a value consensus \u2014 shared values that let society run smoothly. Family, school and media teach cooperation, punctuality and respect, and society holds together.",
    "Their warning is inadequate socialisation: individuals who never learn the shared norms may fail to integrate, producing instability or deviance."],
    ex:{t:"Example — the functionalist picture",b:["Family teaches sharing; school teaches queuing; media praises teamwork.","Millions of strangers can then cooperate daily \u2014 value consensus in action.","For functionalists, that is socialisation doing its job."]}},
   {art:"layers",h:"The conflict views: Marxism",p:[
    "Marxists answer: socialisation mainly serves the capitalist class. It teaches people to accept inequality as normal \u2014 capitalist ideology \u2014 and it reproduces social class, passing advantage and disadvantage down the generations.",
    "A wealthy child is socialised toward confidence, connections and top universities; a working-class child may be socialised to accept \u2018their place\u2019. Same process, very different destinations."],
    ex:{t:"Example — two children, two scripts",b:["Child A\u2019s family buys tutors and expects university; Child B is told \u2018people like us don\u2019t go there\u2019.","Both children learned their lesson well \u2014 that is the problem.","Marxists call this the reproduction of social class."]}},
   {art:"roles",h:"The conflict views: feminism",p:[
    "Feminists focus on gender role socialisation: children are taught what behaviour is \u2018appropriate\u2019 for their gender \u2014 girls nurtured toward caring and appearance, boys pushed toward assertiveness and competition.",
    "The result is that gender inequality gets rebuilt in every generation \u2014 not by law, but by a thousand small lessons in homes, schools and screens."],
    ex:{t:"Example — the lessons add up",b:["A girl praised for being \u2018so helpful\u2019, a boy praised for being \u2018so strong\u2019.","Years of such praise steer them toward different subjects, jobs and pay.","Feminists ask: who benefits from these scripts?"]}},
  ],
  activity:"Watch any advert or film clip. Write down one media representation of gender it contains, and explain how a functionalist and a feminist would each read it differently.",
  check:[
   {q:"Steering children toward 'appropriate' toys and interests is called\u2026",o:["Ostracism","Correlation","Operationalisation","Canalisation"],a:3},
   {q:"Functionalists say socialisation creates\u2026",o:["Social cohesion and value consensus","Only conflict","Nothing at all","Higher prices"],a:0},
   {q:"Feminists highlight socialisation into\u2026",o:["Random hobbies","Sampling frames","Masculine and feminine gender roles","Weather patterns"],a:2},
  ]},

 {id:"t2u6",n:6,title:"Social Control: Keeping Us In Line",mins:180,icon:"Shield",
  summary:"Formal and informal control, positive and negative sanctions \u2014 and the argument about whose order is being kept.",
  keyWords:["social control","formal control","informal control","sanction","conformity"],
  sections:[
   {art:"control",h:"What is social control?",p:[
    "Social control means the ways society encourages people to conform to norms and laws, and discourages deviance. Without it, shared life would collapse \u2014 the argument is about how it works and who it serves.",
    "There are two broad kinds: formal control (official rules enforced by institutions) and informal control (everyday pressure from the people around us)."],
    ex:{t:"Example — control all around you",b:["A speed camera (formal) and a parent\u2019s disappointed look (informal) both change behaviour.","One uses law; the other uses love and shame.","Both are social control."]}},
   {art:"law",h:"Formal vs informal control",p:[
    "Formal social control uses written laws and official institutions \u2014 police, courts, government, school rules \u2014 with official penalties like fines, suspension or prison.",
    "Informal social control uses unwritten expectations enforced through social pressure: praise, teasing, gossip, disapproval, exclusion. It is less visible but often more powerful, because it works everywhere, all the time."],
    ex:{t:"Example — why informal control is strong",b:["A teenager avoids stealing not because of the police\u2026","\u2026but because they cannot face disappointing their parents or losing their friends\u2019 respect.","No officer needed: informal control did the work."]}},
   {art:"scale",h:"Sanctions: the carrots and sticks",p:[
    "Sanctions are society\u2019s responses to behaviour. Positive sanctions reward conformity \u2014 praise, prizes, promotion. Negative sanctions punish deviance \u2014 detention, fines, suspension, imprisonment.",
    "Both formal and informal control use both kinds: a certificate (formal positive), a smile (informal positive), a prison sentence (formal negative), being ignored by friends (informal negative)."],
    ex:{t:"Example — the sanction grid",b:["Formal positive: employee of the month award. Formal negative: a court fine.","Informal positive: applause from friends. Informal negative: the cold shoulder.","Four boxes \u2014 and society uses all of them daily."]}},
   {art:"theory",h:"Consensus vs conflict on social control",p:[
    "Functionalists (consensus) say control is necessary and fair: norms are widely accepted, and conformity benefits everyone \u2014 schools teaching rules create harmony.",
    "Marxists (conflict) reply that control protects the powerful: laws guard property and criminalise the poor. Feminists add that control polices gender: women are steered into caregiver roles and judged more harshly for breaking gender norms."],
    ex:{t:"Example — one law, three readings",b:["A strict anti-loitering law passes.","Functionalist: it keeps streets orderly for all. Marxist: it targets the poor who have nowhere else to be. Feminist: is it enforced equally on men and women?","Same law, three sociological lenses."]}},
  ],
  activity:"Fill your own sanction grid: one real example each of formal positive, formal negative, informal positive and informal negative sanctions from your school or community.",
  check:[
   {q:"Rewards for conforming to norms are called\u2026",o:["Statistics","Negative sanctions","Positive sanctions","Stereotypes"],a:2},
   {q:"A parent's disapproving look is an example of\u2026",o:["A pilot study","Formal social control","Informal social control","A court order"],a:2},
   {q:"Marxists argue social control mainly serves\u2026",o:["Only teenagers","Nobody","The interests of the powerful","Everyone equally"],a:2},
  ]},

 {id:"t2u7",n:7,title:"Formal Control in Action",mins:180,icon:"ClipboardCheck",
  summary:"The five formal agencies \u2014 government, police, courts, penal system, armed forces \u2014 and the methods they use, from law-making to imprisonment.",
  keyWords:["government","police","courts","penal system","coercion","digital surveillance"],
  sections:[
   {art:"law",h:"The five formal agencies",p:[
    "Government makes and oversees the laws that regulate behaviour \u2014 from taxation to environmental rules. Police enforce those laws: investigating crime, making arrests, keeping public order.",
    "Courts interpret the law, judge guilt and set punishments. The penal system (prisons and correction centres) carries punishments out and attempts rehabilitation. The armed forces protect against external threats and may keep internal order in emergencies."],
    ex:{t:"Example — one crime, five agencies",b:["Parliament made theft illegal (government). An officer arrests a thief (police).","A judge sentences them (courts); prison holds and tries to reform them (penal system).","In a national crisis, soldiers might keep order (armed forces)."]}},
   {art:"law",h:"Methods: law-making and coercion",p:[
    "Law-making is the first method: writing rules with penalties attached \u2014 like laws against drink-driving. Clear laws warn everyone of the consequences in advance.",
    "Coercion means using force or the threat of force to ensure compliance \u2014 police controlling a violent protest, for instance. Coercion is powerful but controversial: too much of it can destroy public trust."],
    ex:{t:"Example — the warning built into law",b:["A driving law states the speed limit and the fine.","Most drivers slow down without ever meeting a police officer.","The written law itself did the controlling."]}},
   {art:"measure",h:"Methods: surveillance, arrest, sentencing, imprisonment",p:[
    "Digital surveillance monitors activity \u2014 CCTV on streets, tracking online \u2014 to detect and deter crime, raising a live debate about privacy. Arrest detains suspects; sentencing sets the punishment; imprisonment confines offenders to punish and deter.",
    "Each step is a stronger dose of formal control. Societies argue constantly about the right dose: enough to keep order, not so much that freedom disappears."],
    ex:{t:"Example — the escalating ladder",b:["Camera spots a theft (surveillance) \u2192 suspect detained (arrest) \u2192 judge gives two years (sentencing) \u2192 time served (imprisonment).","Four methods in one case, each more serious.","Formal control is a ladder, not a single tool."]}},
   {art:"control",h:"How effective is formal control?",p:[
    "Formal control is strong at enforcing clear rules with real penalties \u2014 few people ignore tax law or speed cameras entirely. But it cannot watch everyone always, and it works best when informal control supports it.",
    "Where laws clash with what people believe is fair, formal control weakens: rules get broken quietly and enforcement turns heavy-handed. The most orderly societies get both kinds of control pulling together."],
    ex:{t:"Example — when the two controls team up",b:["Seat-belt laws worked best once families and friends ALSO expected belt-wearing.","Law provided the penalty; informal pressure provided the daily reminder.","Formal + informal together beat either alone."]}},
  ],
  activity:"Choose one law you think matters (for example, laws against phone use while driving). Write which agency enforces it, which methods are used, and whether informal control supports or undermines it.",
  check:[
   {q:"Which agency interprets laws and decides punishments?",o:["The media","The courts","The peer group","The family"],a:1},
   {q:"Using force or threats to ensure compliance is\u2026",o:["Cohabitation","Canalisation","Correlation","Coercion"],a:3},
   {q:"CCTV and online monitoring are examples of\u2026",o:["Digital surveillance","Informal control","Positive sanctions","Customs"],a:0},
  ]},

 {id:"t2u8",n:8,title:"Identity in a Connected World",mins:180,icon:"PenLine",
  summary:"Age, gender, ethnicity and class; the digital self; and how globalisation reshapes who we think we are.",
  keyWords:["social identity","digital self","globalisation","hybrid identity","multiculturalism","postmodernism"],
  sections:[
   {art:"identity",h:"Four aspects of social identity",p:[
    "Age positions you: a teenager is expected at school, an elder may be treated as a source of wisdom. Gender carries expectations about behaviour, careers and roles \u2014 expectations societies are actively debating.",
    "Ethnicity \u2014 shared culture, language and heritage \u2014 shapes belonging and, sadly, sometimes the stereotypes and discrimination a person faces. Social class shapes access to resources, education and opportunity. All four combine in every individual."],
    ex:{t:"Example — four aspects, one person",b:["Ngozi: sixteen (age), female (gender), Igbo (ethnicity), from a working-class home (class).","Each aspect brings expectations and opportunities; together they shape her identity.","No single label tells her story."]}},
   {art:"identity",h:"The digital self",p:[
    "Online, people build a second identity \u2014 the digital self \u2014 through profiles, posts and photos. It can be curated: edited to show a chosen version of who we are.",
    "The positives are real: connection with like-minded people, support communities, room to express identity. The negatives are real too: unrealistic comparisons, pressure to perform, and gaps between the online self and the offline life."],
    ex:{t:"Example — two selves",b:["A teenager posts a glamorous feed \u2014 beach shots, brand names \u2014 while living an ordinary life offline.","Meanwhile another finds an online community for a rare condition and finally feels understood.","The digital self can burden or liberate \u2014 often both."]}},
   {art:"global",h:"Globalisation and identity",p:[
    "Globalisation \u2014 the growing connection of countries through trade, media and migration \u2014 pulls identity in three directions. Cultural defence: some societies guard traditions against foreign influence. Hybrid identities: people blend cultures into something new. Homogenisation: global brands and media make cultures more alike.",
    "Cultural diversity and multiculturalism are the bright side: exchange, festivals, understanding. The worry is global culture drowning local traditions."],
    ex:{t:"Example — three directions at once",b:["Japan preserves tea ceremonies (defence); a British-Indian teen mixes saris with streetwear (hybrid); the same films and fast food appear everywhere (homogenisation).","Globalisation does all three simultaneously.","Identity is being renegotiated worldwide."]}},
   {art:"identity",h:"Postmodernism: the pick-and-mix society",p:[
    "Postmodernists argue identity is now chosen rather than given. Class, gender and ethnicity no longer dictate who you must be; individuals assemble identities from lifestyle choices, consumption patterns and digital personas \u2014 a \u2018pick-and-mix\u2019 society.",
    "Examples surround us: the digital nomad who chooses travel over a fixed career; the vegan whose shopping basket states their identity. Critics reply that money still limits the menu \u2014 not everyone can afford every choice."],
    ex:{t:"Example — identity by choice",b:["One person identifies as a gamer, eco-consumer and digital nomad \u2014 none of it assigned at birth.","Their purchases, posts and lifestyle ARE the identity.","Postmodernists call this the pick-and-mix society; critics ask who can afford the shop."]}},
  ],
  activity:"Describe your own identity in two columns: 'Given' (ascribed \u2014 age, ethnicity, family) and 'Chosen' (styles, interests, online persona). Which column do YOU think matters more \u2014 and would a postmodernist agree?",
  check:[
   {q:"The identity people build online through profiles and posts is the\u2026",o:["Digital self","Sampling frame","Hidden curriculum","Penal system"],a:0},
   {q:"Blending elements of different cultures creates\u2026",o:["Hybrid identities","Homogenisation only","A census","Coercion"],a:0},
   {q:"Postmodernists argue identity today is\u2026",o:["Decided only by law","Chosen rather than given","Impossible","Fixed at birth forever"],a:1},
  ]},
];
