const SOC11T2_UNITS=[
 {id:"y2u1",n:1,title:"Education and Schooling",mins:180,icon:"BookOpen",
  summary:"What education and schooling mean, formal vs informal education, and the official and hidden curriculums.",
  keyWords:["education","schooling","formal education","informal education","official curriculum","hidden curriculum"],
  sections:[
   {art:"school",h:"Education versus schooling",p:[
    "Education is the whole process of learning knowledge, skills, values and attitudes \u2014 it happens everywhere, throughout life. Schooling is the formal part of education, usually in institutions like schools and colleges.",
    "So all schooling is education, but not all education is schooling. Sociology studies both the formal system and the everyday learning around it."],
    ex:{t:"Example — learning in two places",b:["Learning algebra in a classroom is schooling.","Learning to cook or share from family is also education.","Schooling is the formal slice of a much bigger process."]}},
   {art:"school",h:"Formal and informal education",p:[
    "Formal education is structured learning guided by a curriculum \u2014 lessons, subjects and tests in schools or colleges. Informal education is unstructured learning outside formal institutions, such as learning social skills at home.",
    "Both matter. Formal education gives qualifications and structured knowledge; informal education gives everyday life skills and values."],
    ex:{t:"Example — formal and informal side by side",b:["A maths lesson with a syllabus and exam is formal education.","Learning manners and teamwork at home is informal education.","A person needs both to function in society."]}},
   {art:"write",h:"The official curriculum",p:[
    "The official curriculum is what a school openly plans to teach: the subjects, syllabus content and tests \u2014 maths, science, history and the rest.",
    "It is written down, examined and reported. It is the visible face of what schooling is for: transmitting knowledge and skills, and measuring them."],
    ex:{t:"Example — the planned lessons",b:["A timetable of English, science and history lessons is the official curriculum.","Exams test what has been taught.","This is the visible, planned part of schooling."]}},
   {art:"control",h:"The hidden curriculum",p:[
    "The hidden curriculum is everything students learn that is NOT openly taught: norms, values, punctuality, conformity, respect for authority and gender roles. It is learned through the way school is organised.",
    "For example, learning to line up, obey the bell and work in a team teaches discipline and cooperation \u2014 lessons no subject openly names but every student absorbs."],
    ex:{t:"Example — the unwritten lessons",b:["Nobody teaches a lesson called \u2018obey the timetable\u2019.","Yet students learn punctuality and respect for authority anyway.","That is the hidden curriculum at work."]}},
  ],
  activity:"List two things you have learned through the official curriculum and two through the hidden curriculum. Explain the difference in your own words.",
  check:[
   {q:"Schooling is best described as\u2026",o:["Only exams","The formal part of education in institutions","Only home learning","All learning everywhere"],a:1},
   {q:"The official curriculum includes\u2026",o:["Only playground games","Nothing planned","Only hidden lessons","Subjects, syllabus and tests"],a:3},
   {q:"Punctuality and respect for authority are taught by the\u2026",o:["Official curriculum only","Government","Family only","Hidden curriculum"],a:3},
  ]},

 {id:"y2u2",n:2,title:"Types of School",mins:180,icon:"Users",
  summary:"The main types of school and the strengths and limitations of each.",
  keyWords:["state school","private school","selective school","single-sex","co-educational","faith school","international school"],
  sections:[
   {art:"school",h:"State and private schools",p:[
    "State (public) schools are government-funded and open to all \u2014 affordable for most families, though sometimes with large class sizes that reduce individual attention.",
    "Private schools are fee-paying and privately funded, often with smaller classes and better facilities \u2014 but their high cost makes them out of reach for many families."],
    ex:{t:"Example — access and cost",b:["A state school is free and open to local children.","A private school offers small classes but charges fees.","Cost shapes who can attend which."]}},
   {art:"target",h:"Selective and non-selective schools",p:[
    "Selective schools admit students based on academic ability or entrance exams \u2014 tailored to high achievers, but excluding those who do not meet the criteria.",
    "Non-selective schools accept all students regardless of ability, promoting equal opportunity, though they may find it harder to meet every individual academic need."],
    ex:{t:"Example — who gets in",b:["A selective school uses an entrance exam to choose students.","A non-selective school takes all local children.","One sorts by ability; the other opens the door to everyone."]}},
   {art:"identity",h:"Single-sex and co-educational schools",p:[
    "Single-sex schools admit only boys or only girls \u2014 which can reduce gender stereotypes in subject choice, but limits social interaction with the opposite gender.",
    "Co-educational schools admit both, encouraging interaction and cooperation between genders, though some argue this can bring distractions."],
    ex:{t:"Example — together or apart",b:["A girls-only school may see more girls choosing science.","A co-ed school mixes boys and girls in every class.","Each arrangement has trade-offs."]}},
   {art:"culture",h:"Faith and international schools",p:[
    "Faith schools are centred on religious teachings, promoting shared values and beliefs, though they may offer a narrower range of perspectives.",
    "International schools offer global curriculums such as Cambridge or IB, preparing students for international opportunities \u2014 but they are often expensive and limited to certain regions."],
    ex:{t:"Example — values and global reach",b:["A faith school builds lessons around shared religious values.","An international school follows a global curriculum like Cambridge.","Both open some doors and narrow others."]}},
  ],
  activity:"Choose three types of school. For each, write one strength and one limitation without using examples \u2014 just clear reasons.",
  check:[
   {q:"State schools are\u2026",o:["Only religious","Fee-paying and private","Government-funded and open to all","Only for high achievers"],a:2},
   {q:"Selective schools admit students based on\u2026",o:["Random choice","Family wealth only","Academic ability or entrance exams","Age only"],a:2},
   {q:"A limitation of private schools is that they\u2026",o:["Teach nothing","Are illegal","Are costly and inaccessible for many","Have no facilities"],a:2},
  ]},

 {id:"y2u3",n:3,title:"Alternatives & the Functionalist View",mins:180,icon:"Lightbulb",
  summary:"Alternative approaches to education, and the functionalist view of what education does for society.",
  keyWords:["online learning","homeschooling","unschooling","vocational learning","meritocracy","role allocation","value consensus"],
  sections:[
   {art:"science",h:"Alternative approaches",p:[
    "Beyond traditional schooling there are alternatives. Online learning uses the internet, offering flexibility but needing self-discipline. Homeschooling is teaching at home, more personalised but with less peer contact.",
    "Unschooling rejects a set curriculum and learns through life experiences \u2014 encouraging independence but risking gaps. Vocational learning teaches practical trade skills; progressive schooling focuses on the whole child through project work."],
    ex:{t:"Example — different routes",b:["A student learns coding through an online course.","Another learns carpentry through vocational training.","Both are alternatives to a standard academic school."]}},
   {art:"achieve",h:"The functions of education",p:[
    "Functionalists see education as serving society. It handles socialisation (teaching norms and values), social control (order and discipline), and an economic function (preparing workers with skills).",
    "It also performs a selective function \u2014 sorting people by ability \u2014 and role allocation, matching talents to future jobs."],
    ex:{t:"Example — sorting for jobs",b:["A student who excels in science may be steered toward medicine.","Education matches their talent to a future role.","Functionalists call this role allocation."]}},
   {art:"chance",h:"Meritocracy and value consensus",p:[
    "Functionalists believe education offers meritocracy and social mobility: success based on ability and effort, not background, so a talented working-class student can rise through scholarships.",
    "Education also builds value consensus \u2014 a shared set of values, like fairness and respect for diversity \u2014 that holds society together. It offers equal opportunities, standardised testing and vocational routes."],
    ex:{t:"Example — rising by merit",b:["A working-class student earns a scholarship through hard work.","They go on to a top university.","Functionalists see this as meritocracy in action."]}},
   {art:"scale",h:"Strengths and limits of the functionalist view",p:[
    "The strength of the functionalist view is that it explains education\u2019s role in social order, stability and integration \u2014 how schooling turns children into functioning members of society.",
    "Its limitation is that it can ignore inequalities of class, gender and ethnicity, and may overlook how education can maintain the status quo rather than change it. The Marxist and feminist views challenge exactly this."],
    ex:{t:"Example — the missing inequalities",b:["Functionalists praise education for creating shared values.","But not everyone gets an equal chance in it.","Critics say functionalism overlooks these inequalities."]}},
  ],
  activity:"Explain meritocracy and role allocation in your own words. Then give one strength and one limitation of the functionalist view of education.",
  check:[
   {q:"Homeschooling means education\u2026",o:["Provided at home instead of school","Banned by law","Only in prisons","Only online"],a:0},
   {q:"Meritocracy means success based on\u2026",o:["Age only","Family wealth only","Random luck","Ability and effort, not background"],a:3},
   {q:"Matching students' talents to future jobs is\u2026",o:["Secularisation","Cohabitation","Role allocation","Coercion"],a:2},
  ]},

 {id:"y2u4",n:4,title:"Marxist & Feminist Views of Education",mins:180,icon:"BarChart2",
  summary:"How Marxists and feminists challenge the functionalist picture: class reproduction, cultural capital, the myth of meritocracy and gendered education.",
  keyWords:["Marxism","reproduction of class","cultural capital","myth of meritocracy","feminism","gendered curriculum","teacher expectations"],
  sections:[
   {art:"gap",h:"The Marxist view: reproducing class",p:[
    "Marxists argue education reproduces class inequalities. It socialises students into capitalist ideology and uses the curriculum as a form of social control, reflecting middle-class values.",
    "\u2018Cultural capital\u2019 \u2014 the language, knowledge and confidence of wealthier families \u2014 gives their children an advantage in a system built around those very things."],
    ex:{t:"Example — cultural capital at work",b:["A middle-class child arrives already familiar with the language of exams and interviews.","A working-class child may not have that head start.","Marxists call this advantage cultural capital."]}},
   {art:"school",h:"Hidden curriculum and the myth of meritocracy",p:[
    "For Marxists, the hidden curriculum teaches obedience and respect for hierarchy \u2014 preparing students to accept their place in a capitalist workforce. The official curriculum teaches the academic content.",
    "They argue meritocracy is largely a myth: education claims to reward ability, but in reality wealthier students have better resources, so the system mainly serves the upper class."],
    ex:{t:"Example — the myth exposed",b:["Education says anyone can succeed through effort.","But wealthy students can afford tutors and better schools.","Marxists call true equal opportunity a myth of meritocracy."]}},
   {art:"identity",h:"The feminist view: gender inequality",p:[
    "Feminists argue education can perpetuate gender inequalities. A patriarchal culture and a male-dominated worldview can limit girls\u2019 opportunities, and role models and power in schools may favour men.",
    "A gendered curriculum can steer subjects by gender \u2014 girls toward humanities or nursing, boys toward engineering or science \u2014 reinforcing wider stereotypes."],
    ex:{t:"Example — steered subjects",b:["Girls may be gently encouraged toward humanities.","Boys may be encouraged toward sciences and engineering.","Feminists call this a gendered curriculum."]}},
   {art:"theory",h:"Teacher expectations and evaluation",p:[
    "Feminists also point to teacher expectations and peer pressure: unconscious gender bias can shape how teachers treat students and what students believe they can achieve.",
    "Each view has limits. Marxism can over-focus on class and neglect race and gender; feminism can oversimplify how gender interacts with class and ethnicity. Both, though, expose inequalities functionalism misses."],
    ex:{t:"Example — expectations shaping results",b:["A teacher may unconsciously encourage boys more in science.","Girls may then doubt their science ability.","Feminists say teacher expectations shape outcomes."]}},
  ],
  activity:"Explain cultural capital and the myth of meritocracy in your own words. Then give one criticism of the Marxist and one of the feminist view.",
  check:[
   {q:"Marxists argue education mainly\u2026",o:["Removes all wealth","Ends capitalism","Reproduces class inequalities","Abolishes exams"],a:2},
   {q:"Cultural capital gives an advantage to\u2026",o:["Only teachers","Wealthier, middle-class students","The poorest students","No one"],a:1},
   {q:"A gendered curriculum tends to\u2026",o:["Remove teachers","Treat all subjects equally","Ban all subjects","Steer subjects by gender"],a:3},
  ]},

 {id:"y2u5",n:5,title:"Achievement & Social Class",mins:180,icon:"ClipboardCheck",
  summary:"The patterns in achievement, and the class-based factors that help explain differences: material, cultural, linguistic and in-school.",
  keyWords:["material factors","cultural capital","linguistic factors","labelling theory","compensatory education","anti-school subculture"],
  sections:[
   {art:"achieve",h:"Patterns in achievement",p:[
    "Achievement and experience vary by social class, ethnicity, gender and between countries. This unit focuses on social class, where students from higher socio-economic backgrounds tend to achieve more.",
    "The reason is not ability alone \u2014 it is the resources, culture and treatment that surround a child. Sociologists group these into material, cultural, linguistic and in-school factors."],
    ex:{t:"Example — the class gap",b:["Wealthier families can afford private tutoring and better schools.","Their children often achieve higher results.","The gap is about resources and support, not just talent."]}},
   {art:"gap",h:"Material and cultural factors",p:[
    "Material factors are about money: poverty limits access to books, technology, private tuition and even a quiet place to study. A lack of home internet, for example, can hold a student back.",
    "Cultural and social factors are about attitudes: middle-class families may place stronger emphasis on academic success and extracurricular activities. Cultural capital gives their children familiarity with the school\u2019s dominant culture."],
    ex:{t:"Example — no quiet space",b:["A student shares a crowded home with no desk or internet.","Homework and revision become far harder.","Material factors have shaped their achievement."]}},
   {art:"talk",h:"Linguistic and home factors",p:[
    "Linguistic factors matter: children from lower-class or minority families may struggle if the school\u2019s language differs from home speech, especially in exams.",
    "Home and community factors count too: a supportive home, where parents engage with a child\u2019s learning, tends to raise achievement. Compensatory education \u2014 free meals, after-school tutoring \u2014 tries to help disadvantaged students."],
    ex:{t:"Example — support at home",b:["Parents who read with a child and ask about school help them achieve.","A child with little home support may fall behind.","Home and community factors shape results."]}},
   {art:"mark",h:"In-school factors",p:[
    "Inside school, pro- and anti-school subcultures shape outcomes: an anti-school group may reject academic success as \u2018uncool\u2019, dragging engagement down.",
    "Labelling theory shows how teachers\u2019 expectations can become self-fulfilling prophecies: a student labelled \u2018lazy\u2019 may disengage and underachieve. Selective and private schools often add better resources on top."],
    ex:{t:"Example — the label sticks",b:["A teacher labels a student \u2018not academic\u2019.","The student stops trying and underachieves.","Labelling created a self-fulfilling prophecy."]}},
  ],
  activity:"List four class-based factors affecting achievement (material, cultural, linguistic, in-school). Explain how each one can hold a student back.",
  check:[
   {q:"Material factors affecting achievement are mainly about\u2026",o:["Height","Star signs","Weather","Money and resources"],a:3},
   {q:"A student labelled 'lazy' who then disengages illustrates\u2026",o:["A self-fulfilling prophecy","Cultural capital","Meritocracy","Secularisation"],a:0},
   {q:"Free school meals and after-school tutoring are examples of\u2026",o:["Private schooling","Cultural capital","Compensatory education","Selective testing"],a:2},
  ]},

 {id:"y2u6",n:6,title:"Achievement & Ethnicity",mins:180,icon:"Target",
  summary:"The factors that help explain ethnic differences in achievement: institutional racism, the ethnocentric curriculum, role models, language and labelling.",
  keyWords:["institutional racism","ethnocentric curriculum","role models","linguistic factors","ethnic subculture","labelling"],
  sections:[
   {art:"law",h:"Institutional racism and the curriculum",p:[
    "Institutional racism means discrimination built into the practices and policies of institutions like schools \u2014 for example, lower teacher expectations for minority students, leading to fewer opportunities.",
    "An ethnocentric curriculum focuses on the dominant culture and can alienate minority students \u2014 for instance, teaching mainly European history while ignoring other cultures\u2019 contributions."],
    ex:{t:"Example — feeling left out",b:["A curriculum covers only the dominant culture\u2019s history.","Minority students see little of their own heritage.","An ethnocentric curriculum can leave them feeling excluded."]}},
   {art:"school",h:"Role models and language",p:[
    "A lack of ethnic-minority role models in schools \u2014 for example, mostly majority-group staff \u2014 can affect minority students\u2019 aspirations and motivation.",
    "Linguistic factors matter where a student\u2019s first language is not the language of instruction; exam performance can suffer while they are still mastering the school\u2019s language."],
    ex:{t:"Example — no one like me",b:["A minority student sees few teachers from their background.","They may struggle to picture success for themselves.","A lack of role models can lower aspiration."]}},
   {art:"roles",h:"Cultural, material and home factors",p:[
    "Cultural, material and social factors interact: some cultures place strong emphasis on education, which can raise achievement, while limited finances can lower it.",
    "Home and community factors also count: families and communities that emphasise academic achievement tend to encourage better performance, whatever the ethnic background."],
    ex:{t:"Example — the value of education",b:["A community that strongly values education encourages its children.","This support can lift achievement.","Cultural and home factors work together."]}},
   {art:"identity",h:"In-school factors and labelling",p:[
    "In-school factors include pro- and anti-school subcultures and ethnic subcultures \u2014 shared experiences that can support or reject school values, for better or worse.",
    "Labelling theory applies again: teachers stereotyping students by ethnicity can create self-fulfilling prophecies, discouraging students and causing underachievement."],
    ex:{t:"Example — supportive study groups",b:["Students from the same background form a study group.","They encourage each other to succeed.","A positive ethnic subculture can raise achievement."]}},
  ],
  activity:"Explain institutional racism and the ethnocentric curriculum in your own words. Then give one way schools could reduce ethnic differences in achievement.",
  check:[
   {q:"Discrimination built into a school's practices is\u2026",o:["Secularisation","Meritocracy","Institutional racism","Cultural capital"],a:2},
   {q:"A curriculum focused only on the dominant culture is\u2026",o:["Hidden","Meritocratic","Ethnocentric","Vocational"],a:2},
   {q:"A lack of ethnic-minority role models can affect students'\u2026",o:["Blood type","Age","Aspirations and motivation","Height"],a:2},
  ]},

 {id:"y2u7",n:7,title:"Achievement & Gender",mins:180,icon:"Sparkles",
  summary:"The factors behind gender differences in achievement: gendered socialisation, teacher expectations, access, subcultures and feminist explanations.",
  keyWords:["gendered socialisation","teacher expectations","access to education","gendered subculture","labelling","patriarchy"],
  sections:[
   {art:"roles",h:"Gendered socialisation and social control",p:[
    "Boys and girls are often socialised differently, producing different academic aspirations and behaviours. Girls may be steered toward humanities, boys toward sciences.",
    "Social control differs too: girls are often more closely supervised and encouraged to avoid risk, which can affect their behaviour and study habits."],
    ex:{t:"Example — different steering",b:["A girl is encouraged toward reading and the arts.","A boy is encouraged toward maths and science.","Gendered socialisation shapes their subject choices."]}},
   {art:"target",h:"Teacher expectations and social factors",p:[
    "Teacher expectations can be gendered: teachers may expect boys to excel in maths and science and girls in reading and writing, subtly shaping performance and subject choice.",
    "Cultural and social factors matter too: in some societies, boys receive more educational opportunities than girls because of traditional gender roles."],
    ex:{t:"Example — expected to excel",b:["A teacher expects boys to be strong in science.","Girls receive less encouragement there.","Teacher expectations shape who pursues science."]}},
   {art:"chance",h:"Access and in-school factors",p:[
    "Access to education can be unequal: in some societies girls face barriers like early marriage or domestic responsibilities, and may drop out, especially in rural areas.",
    "In-school factors include gendered subcultures and pro- or anti-school groups \u2014 for example, boys in an anti-school subculture treating academic success as \u2018uncool\u2019, or a group prioritising appearance over study."],
    ex:{t:"Example — a barrier to access",b:["A girl in a rural area is needed for household work.","She drops out of school early.","Unequal access has shaped her achievement."]}},
   {art:"theory",h:"Labelling and feminist explanations",p:[
    "Labelling theory applies to gender too: stereotyping boys as \u2018disruptive\u2019 can discourage their participation. Feminist explanations argue education can reinforce patriarchal values through a hidden curriculum favouring male-dominated fields.",
    "In many systems girls now outperform boys, especially in subjects like English, partly due to higher expectations and a focus on equality \u2014 yet boys are still more likely to pursue STEM, showing persistent cultural influences."],
    ex:{t:"Example — a changing pattern",b:["Girls now outperform boys in many subjects like English.","Yet boys are still more likely to choose STEM fields.","Gender patterns are shifting but not gone."]}},
  ],
  activity:"Explain how gendered socialisation and teacher expectations can affect achievement. Then describe one way gender patterns in education have changed.",
  check:[
   {q:"Steering boys and girls toward different subjects reflects\u2026",o:["Meritocracy","Gendered socialisation","Colonialism","Secularisation"],a:1},
   {q:"A barrier to girls' access to education in some societies is\u2026",o:["Free tuition","Too many schools","Small classes","Early marriage or domestic duties"],a:3},
   {q:"In many systems today, girls now\u2026",o:["Outperform boys in many subjects","Never attend school","Score zero","Only study science"],a:0},
  ]},

 {id:"y2u8",n:8,title:"Global Differences in Education",mins:180,icon:"Shield",
  summary:"Why educational achievement varies between countries, and how to evaluate the different explanations for achievement.",
  keyWords:["availability of schools","poverty","access for girls","class sizes","digital divide","cultural attitudes"],
  sections:[
   {art:"school",h:"Availability and wealth",p:[
    "Educational achievement varies between countries. A basic factor is the availability of schools: some countries, especially rural areas, lack enough schools, so children may travel long distances.",
    "Poverty and wealth matter hugely: wealthier countries can invest more in facilities and teaching staff, while poorer ones cannot. Money shapes what education a country can provide."],
    ex:{t:"Example — the long walk to school",b:["In some remote areas, children walk far to reach a school.","Others have no nearby school at all.","Availability of schools shapes achievement."]}},
   {art:"sample",h:"Access for girls and class sizes",p:[
    "Access to education for girls varies: cultural and societal barriers, such as early marriage or traditional gender roles, may restrict girls\u2019 schooling in some regions.",
    "Class sizes matter too: overcrowded classrooms with high teacher-to-student ratios, common in some developing nations, can limit personal attention and performance."],
    ex:{t:"Example — a crowded classroom",b:["One teacher faces sixty students in a single room.","Individual help is almost impossible.","Large class sizes can lower achievement."]}},
   {art:"global",h:"Culture and the digital divide",p:[
    "Norms, values and cultural differences shape achievement: where a culture strongly emphasises academic success \u2014 as in parts of East Asia \u2014 outcomes are often strong.",
    "Access to the internet and digital resources creates a digital divide: students in low-income countries with limited internet may struggle, especially with online learning."],
    ex:{t:"Example — the digital divide",b:["A student with fast home internet can research and learn online.","A student with no internet cannot.","This digital divide widens global gaps."]}},
   {art:"scale",h:"Evaluating the explanations",p:[
    "Each explanation has strengths and limits. The social-class explanation links wealth to achievement but ignores non-material factors like attitudes. The ethnicity explanation notes cultural influence but risks stereotyping.",
    "The gender explanation highlights specific barriers but varies widely by region. Global-differences explanations capture big structural inequalities like poverty but can ignore local factors within countries."],
    ex:{t:"Example — comparing two countries",b:["Scandinavian countries: small classes, equality, strong internet \u2192 high achievement.","Some low-income countries: few schools, poverty, barriers for girls \u2192 lower achievement.","Structural factors explain much of the gap."]}},
  ],
  activity:"List four reasons achievement varies between countries. Then choose one explanation of achievement and give one strength and one limitation of it.",
  check:[
   {q:"A basic reason achievement varies between countries is\u2026",o:["The availability of schools","The colour of uniforms","The day of the week","Student height"],a:0},
   {q:"The digital divide refers to unequal access to\u2026",o:["The internet and digital resources","School lunches","Uniforms","Sports fields"],a:0},
   {q:"A limitation of the social-class explanation is that it\u2026",o:["Uses no evidence","Ignores non-material factors like attitudes","Focuses on crime","Ignores wealth"],a:1},
  ]},
];
