const CR_UNITS=[
{id:"cr1",n:1,title:"Introduction to Computers",mins:55,icon:"Lightbulb",summary:"Demystifying the computer as a tool for creativity and empowerment — how input, processing and output work together.",
 keyWords:["hardware","software","input","output","digital literacy"],
 sections:[
  {art:"school",h:"The Girl Who Transformed an Entire Farming Village",p:[
    "A young student named Tanvi visited a rural community library and noticed something troubling. While children her age elsewhere were using devices to learn, create and explore, the children here had never even touched a computer mouse. To them, computers were magical, unattainable devices meant only for scientists or wealthy people in distant cities.",
    "Tanvi decided to demystify technology. She collected used, working computers from donations and set up a basic, accessible computer lab. She sat down with primary school students and guided them through their first interactions with a desktop — not with complex jargon, but by showing them how input devices like a keyboard or mouse translate a person's ideas into output on a screen.",
    "She watched a young girl use a basic painting application to sketch a design for her mother's weaving business. The moment that child realized she could control the machine, the fear vanished. The computer transformed from an intimidating black box into a functional canvas for creativity."],
   ex:{t:"Conclusion",b:["Computers are not consumer toys — they are tools for human empowerment.","Mastering the basics of hardware, software and data processing is the first step toward becoming an active digital creator.","Understanding how a machine works removes the fear of it."]}},
  {art:"layers",h:"Key Ideas",p:[
    "A computer is a machine that takes in information (input), processes it according to a set of instructions, and produces a result (output). Hardware refers to the physical parts of the machine you can touch — the keyboard, mouse, screen, and the internal processor and memory that do the actual computing. Software refers to the instructions and programs that tell the hardware what to do — without software, hardware is just an inert collection of parts.",
    "Input devices, such as a keyboard, mouse, microphone or touchscreen, are how a human communicates an idea or command to a computer. Output devices, such as a screen, speaker or printer, are how the computer communicates its result back to the human. Understanding this simple input-process-output loop is the foundation for understanding every more advanced topic in this course, from programming to robotics.",
    "Data is the raw information a computer works with — numbers, text, images, or sound — and processing is what a computer does to transform that raw data into something useful, following a precise, ordered set of instructions called a program.",
    "Digital literacy — the confident, comfortable ability to use, understand and create with computers — is increasingly a basic life skill, not a specialized one. Students who overcome the initial unfamiliarity with a keyboard or mouse quickly discover that computers are simply tools that amplify whatever they already want to create, explore or solve."]},
  {art:"steps",h:"Your First Steps With a Computer",p:[
    "Practice identifying the input and output devices on any computer you use — which parts let you tell the computer something, and which parts let it tell you something back?",
    "Open a simple application, such as a painting or word-processing program, and spend ten minutes exploring what it can do, paying attention to how your keyboard and mouse actions translate into changes on the screen.",
    "Write down, in your own words, one everyday task a computer helps you do faster or better than doing it by hand, and describe the input, the processing, and the output involved."]}
 ],
 activity:"Write a short paragraph explaining the input-process-output loop using an example from your own daily life (for example, typing a message or searching for a picture).",
 check:[
  {q:"What is the difference between hardware and software?",o:["Hardware is the physical parts of a computer; software is the instructions that tell it what to do","Hardware and software are exactly the same thing","Software is a type of keyboard","Hardware only exists inside robots"],a:0},
  {q:"Which of these is an example of an input device?",o:["A keyboard","A speaker","A printer","A monitor screen"],a:0},
  {q:"What transformed the computer from an intimidating machine into a tool for the young girl in the story?",o:["Realizing she could control it to create something, like a design for her mother's business","Buying a more expensive computer","Avoiding computers altogether","Memorizing programming syntax"],a:0}
 ]},

{id:"cr2",n:2,title:"Computational Thinking",mins:55,icon:"Target",summary:"Decomposition, pattern recognition, abstraction and algorithms — the four-part mental toolkit behind every great problem solver.",
 keyWords:["decomposition","pattern recognition","abstraction","algorithm","computational thinking"],
 sections:[
  {art:"data",h:"The Puzzle Master Who Solved a City's Delivery Crisis",p:[
    "A major regional courier service hit a breaking point. As online shopping grew, delivery drivers were getting stuck in traffic, missing drop-offs, and wasting fuel. The problem felt massive and overwhelming: how do you deliver tens of thousands of packages across a chaotic city every single day without delays?",
    "A young logistics analyst joined the team and realized they were looking at the problem the wrong way. Instead of treating it as one giant headache, she applied computational thinking. First, she used decomposition to break the massive problem into smaller pieces, focusing on one neighborhood at a time. Next, she used pattern recognition to notice that traffic clustered heavily near schools in the morning and markets at noon.",
    "She stripped away irrelevant details, like the color of the delivery vans, through abstraction, and designed a clear, step-by-step rule system — an algorithm — for drivers to follow. This simple, ordered approach cut delivery delays by 40 percent within two weeks, proving that you do not need code to solve a complex problem — you need a structured mind."],
   ex:{t:"Conclusion",b:["Computational thinking is the ultimate problem-solving framework for the modern world.","Breaking down complex issues, spotting patterns, filtering out noise, and building step-by-step workflows lets you solve almost any challenge.","This mindset works whether or not you ever write a line of code."]}},
  {art:"interpret",h:"Key Ideas",p:[
    "Computational thinking is a structured way of solving problems, made up of four core habits of mind that work together: decomposition, pattern recognition, abstraction, and algorithm design. It is called 'computational' because it is exactly how a well-designed computer program approaches a problem, but it is equally useful for solving problems that have nothing to do with computers at all.",
    "Decomposition means breaking a large, overwhelming problem into smaller, more manageable pieces that are each easier to understand and solve on their own. A citywide delivery problem becomes far more tractable once broken down into a single neighborhood, a single time window, or a single driver's route.",
    "Pattern recognition means looking across a problem for repeated structures, trends or similarities that reveal something useful — such as traffic clustering at predictable times — that would otherwise be lost inside a mass of unorganized data. Abstraction means deliberately ignoring irrelevant details so you can focus only on what actually matters for solving the problem, such as ignoring van color while focusing on route timing and volume.",
    "An algorithm is a precise, ordered sequence of steps that reliably produces a solution or result when followed correctly. Writing a good algorithm — whether for a delivery route, a recipe, or a piece of code — requires being specific and unambiguous enough that someone (or something) else could follow the exact same steps and get the exact same result."]},
  {art:"steps",h:"Practicing the Four Habits",p:[
    "Pick a problem from your own life — such as organizing your homework, planning a trip, or tidying a room — and practice decomposition by writing down three or four smaller sub-tasks that make up the bigger task.",
    "Look for a pattern in something you do regularly (for example, what time of day you feel most focused, or which type of homework takes longest) and write down what that pattern tells you.",
    "Practice abstraction by listing which details of your chosen problem actually matter for solving it, and which details you can safely ignore.",
    "Finally, write a short algorithm — a numbered list of clear, ordered steps — that would let someone else complete your chosen task exactly the way you do."]}
 ],
 activity:"Choose a real problem you face (like organizing your school bag every morning) and write it out using all four computational thinking habits: decomposition, pattern recognition, abstraction, and an algorithm.",
 check:[
  {q:"What is decomposition in computational thinking?",o:["Breaking a large, overwhelming problem into smaller, more manageable pieces","Deleting a problem entirely","Making a problem more complicated on purpose","Ignoring a problem until it goes away"],a:0},
  {q:"What did the logistics analyst ignore through abstraction in the delivery story?",o:["The color of the delivery vans","The traffic patterns near schools","The total number of packages","The location of neighborhoods"],a:0},
  {q:"What is an algorithm?",o:["A precise, ordered sequence of steps that reliably produces a result","A type of computer hardware","A random guess","A decorative image"],a:0}
 ]},

{id:"cr3",n:3,title:"Scratch Programming",mins:60,icon:"PenLine",summary:"Visual block-based coding that turns loops, variables and events into drag-and-drop puzzle pieces anyone can master.",
 keyWords:["Scratch","block programming","loop","variable","event"],
 sections:[
  {art:"build",h:"The Young Coder Who Created a Viral Game",p:[
    "An eleven-year-old student noticed that while his school friends loved playing games on screens, none of them had any idea how those games were actually made. When he asked adults how to build a game, they handed him dense textbooks filled with confusing code syntax — semicolons, curly braces, and long lines of text he found boring and difficult to navigate.",
    "Then he discovered visual block programming languages like Scratch. Instead of worrying about spelling mistakes in code text, he could drag and drop colorful logic blocks like puzzle pieces to control characters and animations on screen.",
    "He built a fun, simple whack-a-mole style game. Because Scratch let him see his logic visually — using blocks for loops, variables and event triggers — he mastered core programming concepts within weeks. His game became a hit among his classmates, and the confidence he built gave him a launchpad into more advanced, text-based programming later on."],
   ex:{t:"Conclusion",b:["Visual block programming removes the frustrating barrier of complex code syntax.","Platforms like Scratch let students master loops, variables and events visually.","A simple block-based project can turn a creative idea into a working game or animation almost immediately."]}},
  {art:"sample",h:"Key Ideas",p:[
    "Scratch is a visual, block-based programming language where instructions are represented as colorful, snap-together blocks instead of typed text. Because the blocks are shaped to fit together only in ways that make logical sense, Scratch removes many of the small syntax errors — a missing semicolon or bracket — that frustrate beginners in text-based languages.",
    "A loop is a block of instructions that repeats, either a fixed number of times or until a certain condition is met — for example, making a character spin ten times, or move forward continuously until it touches an edge. Loops are essential because they let you avoid repeating the same instruction over and over manually.",
    "A variable is a named container that stores a changing piece of information, such as a player's score, a character's position, or a countdown timer. Programs become far more powerful once they can remember and update information as they run, rather than only reacting to fixed, unchanging instructions.",
    "An event is a trigger that starts a sequence of blocks running — for example, 'when this sprite is clicked' or 'when the green flag is pressed.' Event-driven thinking, where different blocks of code respond to different triggers, is at the heart of almost all interactive software, from simple games to full mobile apps."]},
  {art:"write",h:"Building Your First Scratch Project",p:[
    "Start with a single sprite (a character) and a single, simple goal — for example, making it move when an arrow key is pressed. Build this using an event block connected to a simple movement block before adding anything more complex.",
    "Add a loop that makes an action repeat, such as a sprite bouncing off the edges of the screen continuously, and test it to see exactly how the loop behaves.",
    "Add one variable — such as a score that increases every time the sprite touches another object — and watch how the program's behavior changes as that variable updates.",
    "Once these three pieces work together, you have already used the same core building blocks — events, loops and variables — that appear in almost every piece of interactive software ever built."]}
 ],
 activity:"Describe (in words or a simple sketch) a small Scratch game idea using at least one event, one loop, and one variable.",
 check:[
  {q:"What is the main advantage of Scratch's visual block programming for beginners?",o:["It removes many small syntax errors like missing semicolons, since blocks only fit together in logical ways","It requires memorizing more code than text-based languages","It cannot be used to build games","It only works on one type of computer"],a:0},
  {q:"What is a loop in programming?",o:["A block of instructions that repeats a fixed number of times or until a condition is met","A type of hardware sensor","A single instruction that runs only once ever","A picture used for decoration"],a:0},
  {q:"What is a variable used for in a Scratch project?",o:["Storing a changing piece of information, such as a score or position","Permanently deleting a sprite","Displaying a fixed, unchangeable image","Connecting to the internet"],a:0}
 ]},

{id:"cr4",n:4,title:"MIT App Inventor",mins:60,icon:"Sparkles",summary:"Turning a smartphone into a development lab — building real, functional mobile apps using visual block logic.",
 keyWords:["MIT App Inventor","mobile app","user interface","database","block logic"],
 sections:[
  {art:"help",h:"The Students Who Built an Emergency Water Safety App",p:[
    "A group of secondary school students living in an area prone to severe seasonal flooding noticed a dangerous communication gap. When heavy rains hit, community water sources would often become contaminated with bacteria, causing widespread illness, yet families had no fast way to know which wells were safe.",
    "The students wanted to build a mobile app to solve this, but they had no experience writing native mobile code. They discovered MIT App Inventor, a platform that allows students to design real, functional smartphone applications using visual block logic, much like Scratch but built specifically for mobile apps.",
    "They designed a user interface with interactive buttons and map pins, connected the app to a simple database logging local water testing results, and added a live alert feature that notified users if a nearby water source was compromised. Their app won a global innovation challenge and helped protect families from water-borne illness."],
   ex:{t:"Conclusion",b:["Mobile apps are a primary doorway to digital services in the modern economy.","MIT App Inventor turns a smartphone from an entertainment device into an active development lab.","Students do not need to wait until university to build real, life-saving technology."]}},
  {art:"build",h:"Key Ideas",p:[
    "MIT App Inventor is a visual, block-based platform, similar in spirit to Scratch, but designed specifically to build working apps for Android smartphones. Like Scratch, it uses drag-and-drop logic blocks instead of typed code, but it adds mobile-specific building blocks for things like buttons, text boxes, maps and notifications.",
    "A user interface, or UI, is everything a person sees and interacts with on the screen — buttons, text fields, images and menus. Designing a clear, simple UI is just as important as the underlying logic, because even a powerful app is useless if people cannot figure out how to use it.",
    "A database is an organized store of information an app can read from and write to — in the water-safety app example, a record of which wells had tested safe or contaminated. Connecting an app's interface to a database is what allows information to be shared, updated and displayed to many different users over time.",
    "A live alert or notification is a message an app pushes directly to a user's phone in response to a specific condition being met, without the user needing to open the app and check manually. Combining a UI, a database, and live alerts is the basic recipe behind an enormous range of real-world mobile applications."]},
  {art:"achieve",h:"Designing Your Own App Idea",p:[
    "Identify one real problem in your community that a simple mobile app could help solve — the more specific and local the problem, the easier it is to design a focused solution.",
    "Sketch a simple user interface for this app on paper: what buttons, text or images would appear on the main screen, and what would each one do when tapped?",
    "Describe what information your app would need to store (its database) and how that information would need to update over time.",
    "Describe one alert or notification your app could send automatically, and exactly what condition would trigger it."]}
 ],
 activity:"Sketch a simple screen design for a mobile app that solves a real problem in your school or community, labeling its buttons and what each does.",
 check:[
  {q:"What is MIT App Inventor primarily used for?",o:["Building real, functional smartphone apps using visual block logic","Writing printed newspapers","Designing physical robots only","Editing video files"],a:0},
  {q:"What is a user interface (UI)?",o:["Everything a person sees and interacts with on an app's screen","A type of database only","A hidden background process invisible to users","A programming language"],a:0},
  {q:"What allowed the water safety app to notify users automatically about contaminated wells?",o:["A live alert/notification feature connected to a database of test results","A printed newsletter","A fixed image with no interactivity","Manual phone calls to every user"],a:0}
 ]},

{id:"cr5",n:5,title:"Introduction to Robotics",mins:55,icon:"Shield",summary:"How sensors, programming and physical actuators combine so robots can work safely and productively alongside people.",
 keyWords:["robotics","sensor","actuator","cobot","automation"],
 sections:[
  {art:"agency",h:"The Factory That Redefined Human Teamwork",p:[
    "Managers at a major automotive assembly plant faced a serious safety and efficiency challenge. Workers on the assembly line were developing chronic injuries from manually pressing stiff rubber seals into car doors all day — a precise, repetitive task that exhausted human muscles. Traditional heavy industrial machines could not help, since they were locked inside safety cages that could crush a worker who stepped too close.",
    "The plant's automation team introduced a new kind of machine: a collaborative robot, or 'cobot.' These robots were designed with smart built-in sensors, programming loops and physical actuators that allowed them to work safely side-by-side with humans, rather than being isolated behind cages.",
    "The robot took over the heavy, repetitive task, applying exactly the same pressure to every door seal without ever tiring. Human workers stepped into a supervisory role, controlling the machine's settings and checking quality. This automated partnership eliminated workplace injuries and boosted output, showing how robotics can enhance human labor rather than simply replace it."],
   ex:{t:"Conclusion",b:["Robotics is the intersection where computer programming meets the physical world.","Robots use input data, processing units and physical output mechanisms to automate difficult tasks.","Modern collaborative robots are designed to expand human capability, not just replace human workers."]}},
  {art:"control",h:"Key Ideas",p:[
    "A robot is a programmable machine that senses information about its environment, processes that information according to its code, and then acts on the physical world through motors or other mechanical parts. This sense-think-act cycle is the robotic equivalent of the input-process-output loop introduced earlier in this course.",
    "A sensor is a component that detects information from the physical world — light, distance, temperature, sound — and converts it into data a robot's program can use. An actuator is the opposite: a component, such as a motor or a mechanical arm, that converts a program's instructions into physical movement or force in the real world.",
    "A collaborative robot, or cobot, is specifically designed to work safely in close proximity to humans, often using sensors to detect nearby people and automatically slow down or stop to avoid injury — a sharp contrast to older industrial robots that had to be kept fully isolated behind physical cages for safety.",
    "Robotics is fundamentally interdisciplinary: it combines mechanical design (the physical body of the robot), electronics (the sensors and circuits), and programming (the logic that decides how the robot responds to what its sensors detect) into a single working system."]},
  {art:"steps",h:"Thinking Like a Robotics Engineer",p:[
    "Pick a repetitive, physically tiring task a person might do (like the door-seal example) and describe what a sensor would need to detect for a robot to perform that task safely.",
    "Describe what actuator (motor, arm, gripper) the robot would need to actually carry out the physical action once its sensors and program had decided what to do.",
    "Explain what safety feature — similar to a cobot's people-detecting sensor — the robot should include to work safely near humans.",
    "Summarize, in your own words, why combining mechanical design, electronics and programming together (rather than any one alone) is necessary to build a working robot."]}
 ],
 activity:"Describe a simple robot you would design to do one repetitive task safely, naming its sensor, its actuator, and one safety feature.",
 check:[
  {q:"What is the sense-think-act cycle in robotics?",o:["A robot senses its environment, processes that information, and then acts using actuators","A robot repeats the same fixed motion forever with no sensors","A robot that only displays information on a screen","A purely decorative machine with no programming"],a:0},
  {q:"What is the main difference between a cobot and a traditional caged industrial robot?",o:["A cobot is designed to work safely alongside humans, often slowing or stopping if a person gets close","A cobot cannot move at all","A traditional robot requires no electricity","A cobot is always smaller than a human hand"],a:0},
  {q:"What does an actuator do in a robot?",o:["Converts a program's instructions into physical movement or force","Only stores data with no physical effect","Displays a picture on a screen","Replaces the need for any sensors"],a:0}
 ]},

{id:"cr6",n:6,title:"Basic Electronics",mins:55,icon:"FlaskConical",summary:"Voltage, current, resistance and simple circuits — the physical laws underneath every electronic device.",
 keyWords:["voltage","current","resistance","circuit","LED"],
 sections:[
  {art:"science",h:"The Solar Lantern That Lit Up a Night Market",p:[
    "A vibrant open-air night market suffered a major power grid failure. Dozens of local traders were plunged into darkness, unable to sell their goods. Many resorted to toxic, smoky kerosene lamps — expensive to run, unpleasant to breathe near, and a constant fire hazard around wooden market stalls.",
    "A group of local students who had just finished a basic electronics workshop stepped in to help. They brought a box of loose components: light-emitting diodes (LEDs), simple resistors, breadboards, rechargeable batteries and small solar cells.",
    "They assembled simple, functional circuits right on the market floor, teaching traders how electricity flows from a source, through a protective resistor, and into an LED to produce clean, bright light. They soldered these components into recycled plastic bottles to create solar-powered safety lanterns. The market lit up again — free of toxic smoke — proving that understanding basic circuit laws can bring light and safety to the real world."],
   ex:{t:"Conclusion",b:["Every advanced digital device on earth is built on the foundational laws of electricity.","Mastering voltage, current, resistance and circuit design lets you safely control electrical energy.","Basic electronics is the hardware foundation for advanced automation and robotics."]}},
  {art:"measure",h:"Key Ideas",p:[
    "Voltage is the electrical 'push' or pressure that drives electric current through a circuit — think of it as similar to water pressure in a pipe. Current is the actual flow of electric charge through the circuit, similar to the flow rate of water through that pipe. Resistance is anything in the circuit that opposes or limits that flow, similar to a narrow section of pipe slowing the water down.",
    "A circuit is a closed loop that electricity can flow around, typically including a power source (like a battery), a load (something that uses the electricity, like an LED), and conductive wires connecting them. If the loop is broken anywhere — a disconnected wire, an open switch — current stops flowing entirely, which is exactly how a simple switch works.",
    "A resistor is a small component specifically designed to limit current flow to a safe level, protecting more delicate components (like an LED) from receiving too much current and burning out. An LED, or light-emitting diode, is a component that produces light when current flows through it in the correct direction.",
    "Understanding these basic quantities — voltage, current and resistance — and how they relate to each other is the essential first step before working with any more advanced electronics, including the microcontrollers and sensors used throughout the rest of this course."]},
  {art:"build",h:"Building a Simple Circuit",p:[
    "Identify the three essential parts you would need to light a single LED safely: a power source, a current-limiting resistor, and the LED itself, connected in a closed loop.",
    "Explain, in your own words, what would happen if you connected the LED directly to a battery with no resistor at all, based on what you now know about current and resistance.",
    "Describe what would happen to the circuit if one wire in the loop was disconnected, and why a closed loop is essential for current to flow.",
    "If you have access to real components, practice building this simple circuit on a breadboard under supervision, and observe how the LED responds when you swap in a resistor of a different value."]}
 ],
 activity:"Draw a simple circuit diagram showing a battery, a resistor, and an LED connected in a closed loop, and label the direction current would flow.",
 check:[
  {q:"What is voltage most similar to, in the water-pipe analogy used in this unit?",o:["Water pressure that pushes water through a pipe","The color of the pipe","The temperature of the water","The material the pipe is made from"],a:0},
  {q:"What is the purpose of a resistor in a simple LED circuit?",o:["To limit current flow to a safe level and protect the LED from burning out","To increase the voltage indefinitely","To store data for later use","To disconnect the circuit permanently"],a:0},
  {q:"What happens to current flow if a circuit's loop is broken at any point?",o:["Current stops flowing entirely","Current flow doubles instantly","Current flow is unaffected","The resistor disappears"],a:0}
 ]},

{id:"cr7",n:7,title:"Arduino Basics",mins:60,icon:"BookOpen",summary:"Programming a tiny, affordable microcontroller to read sensors and control real-world devices automatically.",
 keyWords:["Arduino","microcontroller","sensor input","digital output","code loop"],
 sections:[
  {art:"control",h:"The Smart Greenhouse Created by a Teenager",p:[
    "A fourteen-year-old tech enthusiast noticed his grandfather was struggling to maintain his vegetable garden — forgetting to water the plants during hot afternoons, or accidentally overwatering them during humid days, causing crops to rot. He wanted to build an automatic watering system, but traditional industrial automation equipment was far too expensive and complicated for a teenager to buy and program.",
    "He discovered the Arduino microcontroller: a small, inexpensive, programmable circuit board that acts like a tiny computer brain for physical hardware projects. He connected a simple soil moisture sensor to the Arduino's input pins and a small water pump to its output pins.",
    "He wrote a basic code loop: if the soil moisture drops below a certain level, turn on the water pump for a few seconds; otherwise, keep it off. He enclosed the entire setup in a small waterproof box. The system worked perfectly, monitoring the garden around the clock and watering the crops only when truly necessary."],
   ex:{t:"Conclusion",b:["The Arduino microcontroller is a gateway to physical computing.","Writing code that interacts with physical pins lets students read real-world sensor data and control real devices.","This foundation underlies much of modern engineering and automation."]}},
  {art:"theory",h:"Key Ideas",p:[
    "A microcontroller is a small, self-contained computer built onto a single chip, designed to read inputs (like sensors) and control outputs (like motors or lights) based on a program you write and upload to it. Arduino is one of the most popular, beginner-friendly microcontroller platforms, known for being inexpensive, well-documented and widely supported by a large community of makers.",
    "Input pins on an Arduino connect to sensors — devices that measure something in the physical world, such as soil moisture, temperature, light level, or distance — and convert that measurement into a signal the microcontroller's code can read. Output pins connect to actuators, such as motors, pumps, LEDs or buzzers, that the code can turn on or off, or control more precisely.",
    "A code loop, in the Arduino context, is a program that runs continuously, checking sensor input again and again and reacting according to a simple rule, such as 'if soil moisture is below X, turn on the pump.' This constant checking is what allows an Arduino project to run autonomously, twenty-four hours a day, without needing a person to watch it.",
    "The pattern demonstrated in the smart greenhouse story — read a sensor, compare it to a threshold, then trigger an output — is one of the single most common and useful patterns in all of physical computing, appearing in everything from home thermostats to industrial safety systems."]},
  {art:"build",h:"Designing Your Own Arduino Project",p:[
    "Pick a real, everyday problem that involves monitoring something and reacting automatically — such as watering a plant, turning on a light when it gets dark, or sounding an alert when a door opens.",
    "Identify exactly which sensor you would need as your input (for example, a light sensor, a moisture sensor, or a simple switch) and exactly which actuator you would need as your output.",
    "Write out, in plain language, the simple rule your code loop would follow — 'if [sensor reading] is [condition], then [action]; otherwise, [do nothing / different action].'",
    "Consider what physical housing or protection your project would need, as the greenhouse story used a waterproof box, to survive real-world conditions."]}
 ],
 activity:"Write out the input sensor, output actuator, and simple if-then rule for an Arduino project you would like to build.",
 check:[
  {q:"What is an Arduino?",o:["A small, inexpensive, programmable microcontroller often used for beginner physical computing projects","A type of smartphone app only","A social media platform","A word processing program"],a:0},
  {q:"What rule did the teenager's smart greenhouse code loop follow?",o:["If soil moisture drops below a certain level, turn on the water pump; otherwise, keep it off","Water the plants every hour regardless of moisture level","Never water the plants under any condition","Turn on a light whenever the pump runs"],a:0},
  {q:"Why is a continuously running code loop useful in an Arduino project?",o:["It allows the project to monitor and react automatically around the clock without a person watching it","It uses less electricity than any other approach","It prevents the Arduino from ever needing power","It removes the need for any sensors"],a:0}
 ]},

{id:"cr8",n:8,title:"Simple Robot Projects",mins:65,icon:"ClipboardCheck",summary:"Combining a chassis, a microcontroller brain, sensors and wheels into your first working, autonomous machine.",
 keyWords:["chassis","ultrasonic sensor","obstacle avoidance","debugging","autonomous"],
 sections:[
  {art:"chance",h:"The Automated Delivery Car That Won the Science Fair",p:[
    "A team of students entered a regional youth science fair. Most teams brought standard posters and cardboard models. This team wanted to build something that actually moved and made independent decisions: a miniature, autonomous delivery car that could navigate a maze and drop off a package without any human remote control.",
    "They combined all their beginner knowledge into one physical machine — a basic four-wheel robot chassis, an Arduino brain mounted on top, an ultrasonic distance sensor on the front, and a small battery pack.",
    "Their first test was a failure; the robot drove straight into a wall because their code logic was reversed. Instead of giving up, they used their computational thinking skills to debug the code, carefully refining their loop parameters. On competition day, the little car moved forward, detected an obstacle with its ultrasonic sensor, backed up, turned, and navigated the maze perfectly to deliver its package — winning the grand prize."],
   ex:{t:"Conclusion",b:["Building a simple robot project brings code to life.","Combining a chassis, a microcontroller, sensors and wheels into a working machine proves you have mastered the beginner foundations of this course.","Debugging failures patiently is exactly how real engineers make progress."]}},
  {art:"measure",h:"Key Ideas",p:[
    "A chassis is the physical frame or body of a robot that holds all its other parts together — motors, wheels, the microcontroller, and the battery. Choosing and assembling a stable chassis is often the first physical step in any robotics project, providing the foundation everything else attaches to.",
    "An ultrasonic distance sensor works by sending out a short pulse of sound (beyond human hearing) and measuring how long it takes for the echo to bounce back off a nearby object, allowing a robot to estimate how far away an obstacle is without ever touching it. This is the same basic principle bats and dolphins use to navigate in the dark.",
    "Obstacle avoidance is a behavior where a robot's code continuously checks its distance sensor and changes direction — backing up, turning, or stopping — whenever an object gets too close, allowing the robot to navigate an unpredictable environment autonomously rather than following one fixed, pre-planned path.",
    "Debugging is the disciplined process of finding and fixing errors in code or wiring, usually by testing small pieces at a time, carefully observing what actually happens versus what you expected, and adjusting your logic step by step. The story's 'reversed logic' bug is an extremely common type of mistake — and finding and fixing it, rather than giving up, is what actually makes someone a capable builder."]},
  {art:"steps",h:"Planning Your Own Simple Robot",p:[
    "Sketch the physical layout of a simple robot: where the chassis, wheels, microcontroller, sensor and battery would each sit relative to one another.",
    "Write the obstacle-avoidance rule your robot's code should follow — for example, 'if the distance sensor reads less than 10 centimeters, stop, back up, then turn.'",
    "Predict at least one way your first test might fail (for example, reversed motor wiring, or a sensor mounted at the wrong angle), and describe how you would debug it if it happened.",
    "Describe the final challenge or 'maze' you would want your finished robot to complete successfully."]}
 ],
 activity:"Describe the parts list and one obstacle-avoidance rule for a simple robot car you would like to build, and predict one likely bug you might need to debug.",
 check:[
  {q:"What is a chassis in a simple robot project?",o:["The physical frame or body that holds all the robot's other parts together","A type of programming language","A sensor that measures light","A wireless internet connection"],a:0},
  {q:"How does an ultrasonic distance sensor typically work?",o:["It sends a sound pulse and measures how long the echo takes to return, estimating distance","It takes a photograph of the obstacle","It weighs the obstacle","It reads the obstacle's temperature"],a:0},
  {q:"What was the actual cause of the robot's first failed test in the story?",o:["Reversed code logic that caused it to drive into a wall","A dead battery","A missing wheel","No sensor installed at all"],a:0}
 ]},

{id:"cr9",n:9,title:"Python Programming",mins:60,icon:"PenLine",summary:"Moving from visual blocks to real, text-based code — using Python's clean syntax to automate genuinely tedious tasks.",
 keyWords:["Python","syntax","data structure","automation","script"],
 sections:[
  {art:"data",h:"The Student Who Automated Her School's Timetable",p:[
    "An administrative secretary at a large secondary school spent the first two weeks of every term in a state of stress, manually assigning classrooms, teachers and subjects for over a thousand students. If two classes were accidentally assigned to the same room at the same time, the entire school schedule fell into chaos.",
    "A senior student learning Python programming noticed the secretary's distress and offered to help, knowing that Python excels at handling large blocks of data and executing tedious, repetitive tasks through automation.",
    "She wrote a custom Python script using basic data structures, loops and conditional logic. The script took a raw list of teachers, subjects and rooms, and automatically computed a conflict-free master timetable in seconds, instantly flagging any scheduling conflicts. She had proven that text-based coding is a highly practical skill with immediate, real-world value."],
   ex:{t:"Conclusion",b:["Python is one of the world's most versatile text-based programming languages.","Moving from visual blocks to Python's clean syntax unlocks the ability to manipulate large datasets and automate complex tasks.","Python is also the foundational language behind much of modern artificial intelligence."]}},
  {art:"interpret",h:"Key Ideas",p:[
    "Python is a widely used, text-based programming language known for its clean, readable syntax — code that closely resembles plain English instructions, which makes it a popular first text-based language for students moving on from visual block tools like Scratch.",
    "A data structure is a way of organizing multiple pieces of related information together so a program can work with them efficiently — for example, a list of every student's name, or a table pairing teachers with the subjects they teach. Choosing the right data structure makes a program both easier to write and far faster to run.",
    "Loops and conditional logic, first introduced visually in Scratch, work the same way in Python but are written as typed code instead of blocks: a loop repeats a set of instructions, while a conditional statement (an 'if' statement) runs different instructions depending on whether something is true or false — such as whether two classes have been assigned the same room at the same time.",
    "Automation, in the context of this unit, means writing a script — a program designed to perform a specific task — that can complete in seconds a task that would otherwise take a person hours of tedious, error-prone manual work, exactly as the timetable script did for the school secretary."]},
  {art:"write",h:"Thinking Through Your Own Automation Script",p:[
    "Identify a repetitive, tedious task you or someone you know does by hand regularly — sorting a list, checking for duplicates, or organizing information into groups.",
    "Describe what data structure would best represent the information involved (for example, a list of names, or a table pairing two related pieces of information).",
    "Write out, in plain language, the loop and conditional logic your script would need — what would it check on each pass through the data, and what would it do differently depending on the result?",
    "Describe what the finished script would output once it finished running, and how that output would save time compared to doing the task manually."]}
 ],
 activity:"Describe, in plain language, a Python script you could write to automate one tedious task in your own life or school, including its data structure, loop, and conditional logic.",
 check:[
  {q:"What is Python best known for, as described in this unit?",o:["Clean, readable, text-based syntax well suited to handling data and automating tasks","Being a purely visual, block-based language","Only working on robots, never on ordinary computers","Requiring no logic or structure at all"],a:0},
  {q:"What problem did the Python timetable script solve for the school secretary?",o:["It automatically computed a conflict-free master timetable in seconds instead of hours of manual work","It replaced the need for teachers entirely","It designed the school building","It printed physical timetables on paper only"],a:0},
  {q:"What is a data structure, as defined in this unit?",o:["A way of organizing multiple pieces of related information so a program can work with them efficiently","A type of computer monitor","A physical robot chassis","An electrical circuit component"],a:0}
 ]},

{id:"cr10",n:10,title:"Artificial Intelligence",mins:65,icon:"Lightbulb",summary:"How neural networks learn from data to recognize patterns — and why coding AI is different from simply using it.",
 keyWords:["artificial intelligence","neural network","training data","accuracy","pattern recognition"],
 sections:[
  {art:"science",h:"The Teenager Who Built an Early Cancer-Detection AI Tool",p:[
    "A teenager watched a close family member battle cancer, and learned that early, accurate diagnosis is one of the most critical factors in surviving the disease. She noticed that doctors often struggled to interpret complex medical data patterns quickly, and wondered whether computers could be trained to spot these subtle patterns faster and more reliably than the human eye.",
    "She had no medical degree, but she understood the fundamentals of artificial intelligence, and learned how to write code for an artificial neural network — a computer program loosely modeled on the structure of the human brain.",
    "She fed her AI program a large set of anonymized medical data from past cancer cases, training the algorithm to recognize the microscopic differences between benign anomalies and dangerous, malignant cells. Her completed model achieved a very high accuracy rate in detecting cancer samples and was made available for doctors worldwide to use for free — proof that even a student who masters the fundamentals of AI can build tools with genuine, global impact."],
   ex:{t:"Conclusion",b:["Artificial Intelligence is reshaping the landscape of every human industry.","Learning to code neural networks and handle data, rather than only consuming finished AI tools, is what transforms a student into a true architect of this technology.","Real-world AI projects can have life-saving impact even when built by a student."]}},
  {art:"data",h:"Key Ideas",p:[
    "Artificial Intelligence, or AI, refers to computer systems designed to perform tasks that typically require human intelligence — recognizing patterns, understanding language, or making predictions — rather than simply following a fixed, hand-written set of instructions for every possible situation.",
    "A neural network is a specific type of AI model loosely inspired by how neurons in a human brain are connected, made up of many simple, connected units that adjust their internal settings as they are shown more and more examples, gradually becoming better at recognizing patterns in data.",
    "Training data is the set of examples — such as thousands of medical scans, each correctly labeled as benign or malignant — that a neural network learns from. The quality and quantity of training data has an enormous effect on how well the resulting AI model performs; a model trained on poor or biased data will make poor or biased predictions.",
    "Accuracy is a measure of how often an AI model's predictions turn out to be correct when tested against known, correct answers it was not directly trained on. Building a genuinely useful AI tool — as opposed to simply using an existing one — requires learning how to select, clean and structure good training data, and how to measure whether a model's accuracy is truly good enough to trust for a real task."]},
  {art:"ethics",h:"Thinking Responsibly About AI",p:[
    "Consider a real-world problem you would like an AI model to help solve, and describe what kind of training data it would need to learn from.",
    "Think about what could go wrong if that training data were incomplete, biased, or unrepresentative of the real world — how might that affect the model's predictions?",
    "Describe why measuring a model's accuracy honestly, on new examples it has not seen during training, matters before trusting it for something important, such as a medical diagnosis.",
    "Reflect on the difference between simply using an AI-powered app someone else built and actually understanding how the underlying model was trained — why might the second skill matter for your own future?"]}
 ],
 activity:"Describe a real problem where an AI model could help, what training data it would need, and why checking its accuracy honestly matters before trusting its predictions.",
 check:[
  {q:"What is a neural network?",o:["An AI model loosely inspired by connected neurons in the human brain, which learns from examples","A type of physical robot chassis","A wireless internet router","A simple if-then rule with no learning involved"],a:0},
  {q:"Why does the quality of training data matter so much for an AI model?",o:["Poor or biased training data leads to poor or biased predictions","Training data has no effect on the model's performance","AI models do not require any training data","More training data always guarantees perfect accuracy regardless of quality"],a:0},
  {q:"What does 'accuracy' measure in the context of an AI model?",o:["How often the model's predictions turn out to be correct against known answers","How fast the model was built","How expensive the model was to train","How many people use the model"],a:0}
 ]},

{id:"cr11",n:11,title:"Internet of Things (IoT)",mins:60,icon:"Video",summary:"Connecting physical sensors to the cloud so everyday objects can report data, trigger alerts, and be monitored remotely.",
 keyWords:["IoT","sensor network","cloud dashboard","telemetry","connectivity"],
 sections:[
  {art:"global",h:"Saving a Town's Water Grid via Cloud Interactivity",p:[
    "A remote community water district was losing a large share of its clean water supply to hidden underground pipe leaks. Because the pipes were buried deep underground, maintenance teams had no idea a leak existed until a sinkhole opened up or a neighborhood faucet ran dry. Manual line inspection was far too slow to catch the damage in time.",
    "A team of youth tech innovators deployed an Internet of Things (IoT) network to save the town's water supply, installing digital flow-rate sensors along the main water lines and connecting them to Wi-Fi-enabled microcontrollers.",
    "They wrote a program that constantly pushed live flow data to a cloud-based dashboard. If a sensor upstream recorded far more water passing through than a sensor downstream, the cloud system instantly recognized the anomaly, triggered a live map alert, and pinned the exact location of the leak for the repair crew — stopping the water loss within minutes."],
   ex:{t:"Conclusion",b:["The Internet of Things bridges the gap between physical objects and global internet data systems.","Connecting microcontrollers to cloud servers lets students build smart homes, automated industries, and responsive monitoring networks.","Real-time data from many connected sensors can reveal problems invisible to any single observer."]}},
  {art:"data",h:"Key Ideas",p:[
    "The Internet of Things, or IoT, refers to a network of physical devices — sensors, microcontrollers, appliances — that are connected to the internet and can send and receive data automatically, without a person manually operating each one.",
    "A cloud dashboard is a website or app, hosted on remote servers rather than any single device, where data from many connected sensors can be gathered, displayed and monitored in one place, often in real time. This lets a small team monitor a large, spread-out system — like an entire town's water network — from a single screen.",
    "Telemetry is the general term for automatically measuring data at a distance and transmitting it back to a central system for monitoring — exactly what the flow-rate sensors were doing as they continuously reported readings back to the cloud dashboard in the story.",
    "Anomaly detection, as used in the water-leak example, means automatically comparing related pieces of data against each other (like flow readings at two points along the same pipe) to spot something unusual — a difference that signals a likely problem — far faster and more reliably than a human manually reviewing the same numbers."]},
  {art:"control",h:"Designing Your Own IoT System",p:[
    "Pick a real-world system you would like to monitor remotely — for example, the temperature in a greenhouse, the water level in a tank, or whether a door has been left open.",
    "Describe what sensor you would need, and what specific data it would send to a cloud dashboard.",
    "Describe what pattern in the data would count as an 'anomaly' worth alerting someone about, similar to the mismatched flow readings in the water-leak story.",
    "Describe who should receive the alert, and what action they should take once they see it."]}
 ],
 activity:"Design a simple IoT monitoring system for a real-world problem, describing the sensor, the data it sends to the cloud, and the anomaly that would trigger an alert.",
 check:[
  {q:"What does IoT stand for and generally refer to?",o:["Internet of Things — a network of physical devices connected to the internet that send and receive data automatically","A single, standalone computer with no internet connection","A type of programming language","A physical robot chassis only"],a:0},
  {q:"What is a cloud dashboard used for in an IoT system?",o:["Gathering and displaying data from many connected sensors in one place, often in real time","Physically repairing broken pipes","Replacing the need for any sensors","Printing paper reports only"],a:0},
  {q:"How did the IoT system detect the exact location of the water leak in the story?",o:["By comparing flow readings at two points along the pipe and spotting the mismatch as an anomaly","By sending a human inspector to walk the entire pipeline","By guessing randomly","By shutting off all water to the town"],a:0}
 ]},

{id:"cr12",n:12,title:"Robotics Programming",mins:65,icon:"Target",summary:"Pathfinding algorithms, coordinate mapping and state machines that let a robot navigate and adapt without human remote control.",
 keyWords:["pathfinding","state machine","autonomous navigation","obstacle recalculation"],
 sections:[
  {art:"control",h:"The Autonomous Rover That Saved Miners Underground",p:[
    "A sudden structural collapse occurred inside an old underground mining shaft, trapping workers deep behind unstable rock and debris. Sending human rescuers into the dark, crumbling tunnel was far too dangerous — another collapse could happen at any moment, and the tunnel was filled with toxic dust and unpredictable obstacles.",
    "The engineering team deployed an autonomous robotic exploration rover, one that required advanced robotics programming — not a simple remote-controlled toy — to survive the environment. Its code was packed with pathfinding algorithms and coordinate mapping instructions.",
    "As the rover crawled over jagged rocks, its laser scanners built a live 3D map of the tunnel. When its path was completely blocked by a fallen beam, the robot's onboard code dynamically recalculated a new route around the obstacle without waiting for human instructions, eventually locating the trapped miners and relaying their exact coordinates to the surface."],
   ex:{t:"Conclusion",b:["Robotics programming transforms static metal and wire into an intelligent, adaptive machine.","Mastering pathfinding algorithms, locomotion logic and state machines lets you build autonomous rovers for extreme environments.","Real autonomy means recalculating a plan when the world does not match your expectations."]}},
  {art:"theory",h:"Key Ideas",p:[
    "A pathfinding algorithm is a set of instructions a robot's code follows to figure out a route from its current position to a target destination, especially when obstacles are in the way. Good pathfinding algorithms can recalculate a new route automatically the moment an obstacle blocks the original plan, exactly as the mining rover did when it hit a fallen beam.",
    "Coordinate mapping means representing the robot's physical environment as a set of positions or coordinates the code can reason about mathematically — allowing the robot to know not just what it senses right now, but where it is relative to everything it has already explored.",
    "A state machine is a way of organizing a robot's behavior into a set of distinct 'states' (such as 'exploring', 'blocked', 'returning') with clear rules for when the robot switches from one state to another. This structure makes complex robot behavior easier to design, test and debug, since each state only needs to handle a smaller, more specific set of decisions.",
    "Autonomy, in robotics, specifically means the ability to make decisions and adapt to unexpected situations without a human operator controlling every single movement in real time — the defining difference between a simple remote-controlled toy and a genuinely autonomous robot like the rescue rover."]},
  {art:"search",h:"Designing an Autonomous Navigation Behavior",p:[
    "Sketch a simple map with a start point, a target destination, and at least one obstacle in between, and describe the route a robot should take to reach the target.",
    "Describe what should happen in your robot's code if it encounters an obstacle exactly where you expected clear space — how should it recalculate its route?",
    "List two or three distinct 'states' your robot's behavior could be organized into (such as exploring, avoiding, or returning), and describe the rule that would cause it to switch between them.",
    "Explain, in your own words, why a rover exploring a genuinely unknown environment (like a collapsed mine) needs autonomy rather than relying on a human operator's remote control."]}
 ],
 activity:"Design a simple state machine (2-3 states) for an autonomous rover exploring an unknown space, describing what triggers a switch between each state.",
 check:[
  {q:"What is a pathfinding algorithm used for in robotics?",o:["Figuring out a route from a robot's current position to a target destination, adapting when obstacles appear","Measuring a room's temperature","Displaying a fixed image on a screen","Charging a robot's battery"],a:0},
  {q:"What is a state machine in robotics programming?",o:["A way of organizing a robot's behavior into distinct states with clear rules for switching between them","A type of battery charger","A single fixed instruction with no branching logic","A physical wheel mechanism"],a:0},
  {q:"What made the mining rescue rover genuinely autonomous rather than simply remote-controlled?",o:["It could recalculate its own route and make decisions without waiting for human instructions","It was operated entirely by a joystick","It could only move in a straight line","It required a human to press a button for every single movement"],a:0}
 ]},

{id:"cr13",n:13,title:"Sensors and Automation",mins:60,icon:"Shield",summary:"Closed-loop feedback systems that read real-world signals and automatically respond to protect critical processes.",
 keyWords:["sensor feedback","automation loop","failsafe","closed-loop system"],
 sections:[
  {art:"measure",h:"The Automated Supply Chain That Kept Vaccines Cold",p:[
    "A global health organization faced a major logistics challenge: distributing sensitive medical vaccines to remote clinics. If the vaccines' temperature rose above a critical threshold for even a short time, their chemical structure would break down, rendering the entire batch useless. Relying on manual human checks left the process prone to error during long transit shifts.",
    "The logistics facility implemented an advanced sensor and automation system across its supply chain, deploying sensitive digital temperature sensors inside every storage crate, wired into an automated feedback system.",
    "The moment a shipping container's internal temperature ticked upward, the sensor triggered an automation loop: cooling compressors automatically switched on, backup battery power engaged, and a live alert was sent to a central monitoring dashboard. Not a single batch of medicine was lost, showing how automated sensor systems can protect high-value supply chains far more reliably than manual checks alone."],
   ex:{t:"Conclusion",b:["Sensors and automation form the nervous system of modern industrial technology.","Reading sensor data and writing closed-loop feedback systems lets you design machinery that monitors and controls real-world environments.","Automated failsafes catch problems faster and more reliably than manual human checks."]}},
  {art:"control",h:"Key Ideas",p:[
    "A closed-loop feedback system is one where a sensor continuously measures a real-world condition, compares it against a target value, and automatically triggers an action to correct any difference — exactly as the temperature sensors triggered the cooling compressors the moment the reading rose above the safe threshold.",
    "Automation, in this context, is the practice of letting a system respond to sensor data on its own, according to pre-written rules, rather than waiting for a person to notice a problem and react manually. This matters most in situations where delays or human error could be extremely costly, such as spoiled vaccines or an unsafe industrial process.",
    "A failsafe is a backup mechanism designed to activate automatically if the primary system fails — such as backup battery power engaging if the main power source is interrupted — ensuring that a single point of failure does not cause a complete disaster.",
    "Designing a good automated system requires thinking carefully not just about the 'normal' case, but about what should happen when something goes wrong: what sensor reading counts as a warning sign, what action should be triggered automatically, and what backup plan exists if that first action is not enough."]},
  {art:"steps",h:"Designing Your Own Feedback System",p:[
    "Choose a real-world process that needs to stay within a safe range (such as temperature, water level, or light exposure) and describe what sensor would monitor it.",
    "Describe the target value or safe range for that sensor reading, and what automatic action should trigger the moment the reading moves outside that range.",
    "Describe one failsafe backup mechanism that should activate if the first automatic action is not enough to fix the problem.",
    "Describe how a human supervisor should be alerted, and what information they would need to see on a dashboard to understand what happened."]}
 ],
 activity:"Design a closed-loop feedback system for a real-world process, describing its sensor, its safe range, its automatic response, and one failsafe backup.",
 check:[
  {q:"What is a closed-loop feedback system?",o:["A system where a sensor measures a condition, compares it to a target, and automatically triggers a corrective action","A system with no sensors at all","A manual process requiring a human at every step","A system that never changes its behavior"],a:0},
  {q:"What triggered the cooling compressors to switch on automatically in the vaccine story?",o:["A rising temperature reading from the sensors inside the storage crate","A scheduled daily timer with no sensor involved","A manual phone call from a warehouse worker","A random computer error"],a:0},
  {q:"What is a failsafe designed to do?",o:["Activate automatically as a backup if the primary system fails","Permanently shut down the entire system with no recovery","Replace the need for any sensors","Increase costs with no safety benefit"],a:0}
 ]},

{id:"cr14",n:14,title:"Drone Technology",mins:60,icon:"Sparkles",summary:"Autonomous flight paths, payload mechanics and safety protocols that turn quadcopters into powerful tools for real-world impact.",
 keyWords:["drone","autonomous flight path","payload","waypoint navigation"],
 sections:[
  {art:"planet",h:"Reforesting a Burned Mountain in Two Days",p:[
    "A massive wildfire swept through a national park, destroying thousands of acres of forest on a steep mountain range. Environmental teams wanted to replant trees immediately to prevent severe soil erosion, but the terrain was far too steep and dangerous for human volunteers to climb and dig holes safely, and traditional hand-planting would have taken years.",
    "The conservation team turned to advanced drone technology, deploying an automated fleet of heavy-lift quadcopters rather than standard recreational drones. They programmed the fleet to fly in a highly precise grid pattern over the burn zone using automated flight paths.",
    "The drones were equipped with mechanical firing canisters filled with pre-germinated 'seed bombs' packed with nutrient soil. As the drones flew on autopilot, their onboard microcontrollers fired seeds into the ground at the exact depth and spacing required for optimal growth. The automated fleet mapped and planted the entire mountain range in under 48 hours."],
   ex:{t:"Conclusion",b:["Modern drone technology is revolutionizing aviation, agriculture, logistics and cinematography.","Mastering flight dynamics, autonomous waypoint navigation, payload mechanics and safety protocols opens the door to the commercial drone industry.","Automated drone fleets can accomplish tasks impossible for humans working alone."]}},
  {art:"chart",h:"Key Ideas",p:[
    "A drone, or unmanned aerial vehicle, is a flying machine controlled either remotely by a human pilot or autonomously by onboard programming, sensors and flight-control software. Commercial and research drones typically use several rotors (as in a quadcopter) for stable, controllable flight.",
    "Autonomous flight paths, sometimes called waypoint navigation, allow a drone to be programmed with a specific sequence of GPS coordinates to fly to, in order, without a human actively steering it moment to moment — exactly as the seed-planting fleet flew a precise grid pattern over the mountain automatically.",
    "A payload is whatever cargo or equipment a drone carries and deploys during its flight — in the reforestation example, canisters of seed bombs; in other applications, a camera, a medical supply package, or a sensor. Payload mechanics involves designing how and when that cargo is released or deployed with the precision the mission requires.",
    "Safety protocols in drone operation include maintaining a safe distance from people and property, respecting airspace regulations, and building in fail-safes such as automatic landing if the drone loses its GPS signal or battery power runs critically low — all essential given that a drone is a physical, sometimes heavy object flying through shared airspace."]},
  {art:"steps",h:"Planning a Drone Mission",p:[
    "Choose a real-world task a drone could help with (delivering supplies, monitoring crops, mapping a disaster area) and describe the payload it would need to carry.",
    "Describe the flight path the drone would need to follow — where would it start, what waypoints would it pass, and where would it need to end?",
    "Describe one safety protocol the mission would need, such as a minimum safe altitude or a rule for what happens if the battery runs low mid-mission.",
    "Explain why this particular task would be difficult, slow, or dangerous for humans to do without a drone."]}
 ],
 activity:"Plan a simple drone mission for a real-world task, describing its payload, flight path, and one important safety protocol.",
 check:[
  {q:"What is 'autonomous flight path' or waypoint navigation in drone technology?",o:["Programming a drone to fly to a sequence of coordinates automatically, without a human actively steering it","Manually flying a drone with a joystick the entire time","A drone that can only ever fly in a single straight line","A drone with no navigation capability at all"],a:0},
  {q:"What was the drone fleet's payload in the reforestation story?",o:["Canisters of pre-germinated seed bombs packed with nutrient soil","Fire extinguishing chemicals","Medical supplies","Camera equipment only"],a:0},
  {q:"Why is a safety protocol like automatic landing on low battery important for drones?",o:["Because a drone is a physical, sometimes heavy object flying through shared airspace, and losing power mid-flight could cause harm","Because it makes the drone fly faster","Because it is required only for toy drones","Because it has no real safety purpose"],a:0}
 ]},

{id:"cr15",n:15,title:"Machine Learning for Kids",mins:60,icon:"FlaskConical",summary:"Training a computer vision model to recognize and sort objects — and thinking carefully about the ethics of automated decisions.",
 keyWords:["machine learning","image classification","training model","algorithmic ethics"],
 sections:[
  {art:"data",h:"The App That Sorts Plastic Waste in One Click",p:[
    "A primary school group noticed a frustrating pattern in their cafeteria's recycling bins: students kept throwing plastic bottles into the paper bins and food waste into the plastic bins, contaminating entire batches of recycling and making them useless to process. Standing by the bins to direct classmates only worked while someone was actually there.",
    "A couple of tech-savvy students decided to build an automated solution using machine learning tools designed for young learners, aiming to train a computer vision model to sort trash automatically.",
    "They used a webcam to take hundreds of photos of plastic bottles, aluminum cans and paper wrappers from different angles, feeding these labeled images into a machine learning classification engine. They trained the model until it could recognize a new piece of trash it had never seen before, and connected it to a smart bin with an automated sorting lid. When a student held an item up to the camera, the model identified the material in a fraction of a second and opened the correct bin automatically."],
   ex:{t:"Conclusion",b:["Machine learning allows computers to learn patterns from data without being explicitly programmed for every single case.","Introducing students to data classification, image recognition and algorithmic ethics demystifies the technology behind search engines and self-driving cars.","Even a small, well-scoped project can make a genuine difference to a real problem like classroom recycling."]}},
  {art:"interpret",h:"Key Ideas",p:[
    "Machine learning is a type of artificial intelligence where a model improves at a task by being shown many labeled examples, rather than being given a fixed, hand-written rule for every possible case — closely related to the neural networks introduced in the AI unit, but focused here on a very concrete, hands-on classification task.",
    "Image classification is a common machine learning task where a model is trained to sort images into predefined categories — in this case, 'plastic', 'metal' and 'paper' — based on patterns it detects in the pixels of each photo, patterns too subtle or numerous for a person to describe as a simple, explicit rule.",
    "Training a model means repeatedly showing it labeled examples (a photo of a plastic bottle, tagged 'plastic') until it becomes reliably accurate at correctly labeling new, unseen examples of the same categories — the more varied and representative the training photos, the better the model generalizes to real-world use.",
    "Algorithmic ethics means thinking carefully about the consequences, fairness and limitations of an automated decision-making system — for example, considering what should happen if the smart bin misidentifies an item, whether the training photos represented enough variety of real trash, and who is responsible if the system makes a mistake with real consequences."]},
  {art:"ethics",h:"Building and Questioning Your Own Classifier",p:[
    "Choose a simple, real classification task you could imagine training a model for (sorting types of fruit, recognizing different school uniforms, identifying different types of paper) and describe the categories it would need to distinguish.",
    "Describe what a good, varied set of training photos would need to include to make your model reliable across different lighting, angles, and real-world conditions.",
    "Consider what should happen automatically if your model is not confident about which category an item belongs to — should it guess, or ask for human help?",
    "Reflect on one ethical question your project should consider, such as fairness across different types of items or what happens when the system makes a mistake."]}
 ],
 activity:"Describe a simple image classification project you could build, including its categories, what training photos it would need, and one ethical consideration to keep in mind.",
 check:[
  {q:"What is image classification, as described in this unit?",o:["Training a model to sort images into predefined categories based on patterns in the pixels","Printing a photograph on paper","Deleting unwanted images automatically","Compressing an image's file size"],a:0},
  {q:"What made the smart bin's sorting lid open to the correct bin automatically?",o:["A trained machine learning model recognizing the material in the image from the camera","A random guess","A fixed manual switch operated by a teacher","A barcode scanner only"],a:0},
  {q:"What is algorithmic ethics concerned with?",o:["Thinking carefully about the consequences, fairness and limitations of an automated decision-making system","Making a program run faster with no other consideration","Choosing a decorative color scheme for an app","Avoiding the use of any sensors"],a:0}
 ]},

{id:"cr16",n:16,title:"Capstone Innovation Project",mins:90,icon:"Users",summary:"Combining software, electronics, sensors, robotics and cloud connectivity into one working system — a professional-grade proof of skill.",
 keyWords:["capstone project","integration","portfolio","innovation challenge"],
 sections:[
  {art:"achieve",h:"The Teenagers Who Swept the Global Innovation Stage",p:[
    "A group of advanced academy students reached the end of a comprehensive coding and robotics training program. They knew a paper certificate carries little weight in the competitive global tech ecosystem — recruiters, investors and top engineering universities look for verifiable proof of real-world execution. They decided to treat their final capstone innovation project as a genuine product launch rather than just a school assignment.",
    "They combined every advanced module they had learned into one system: a Python-based software core running a custom machine learning vision model; a physical robotic chassis with integrated sensors and automation; a connection to the cloud using an Internet of Things telemetry network; and an automated mobile app interface allowing users to view the system's data remotely.",
    "Their completed project — an autonomous agricultural rover that detects crop diseases and deploys targeted organic treatments — won first place at an international innovation challenge. They were offered university scholarships and seed funding to launch their project as a real startup, proving that a comprehensive capstone portfolio project can be the ultimate launchpad for a career in technology."],
   ex:{t:"Conclusion",b:["The Capstone Innovation Project is the ultimate demonstration of your transformation into an advanced digital innovator.","Combining software, electronics, robotics and cloud connectivity into a single functional machine proves elite technical capability.","A working, integrated system speaks louder than any certificate alone."]}},
  {art:"global",h:"Key Ideas",p:[
    "A capstone project is a final, integrative project designed to combine everything learned throughout a course into one coherent, working system, rather than practicing each skill in isolation. In this course, that means bringing together computational thinking, programming (visual or text-based), electronics, sensors, robotics programming, IoT connectivity, and — for advanced projects — machine learning.",
    "Integration is the technical and organizational challenge of making separately-built pieces work together correctly as one system — for example, ensuring a machine learning vision model's output correctly triggers a physical robotic actuator, which in turn reports its status back to a cloud dashboard. Integration is often harder than building any single piece alone, because small mismatches between components can cause the whole system to fail even when each part works individually.",
    "Portfolio value refers to how a finished, working project demonstrates real, verifiable capability to someone evaluating you — a university admissions officer, a scholarship committee, or a future employer — in a way that a list of completed modules or a certificate alone cannot. A working robot that a judge can watch operate is far more convincing than a claim of having 'learned robotics.'",
    "Presenting a capstone project professionally — a clear explanation of the problem it solves, a live or recorded demonstration, and an honest account of what worked and what you had to debug along the way — is itself a skill worth practicing, since the ability to communicate technical work clearly is just as valuable as the ability to build it."]},
  {art:"culture",h:"Planning Your Own Capstone Project",p:[
    "Choose one real problem you care about, and describe which modules from this entire course (computational thinking, a programming language, electronics, sensors, robotics, IoT, or machine learning) you would combine to address it.",
    "Sketch how the different pieces of your project would need to connect and communicate with each other — for example, how a sensor's reading would need to trigger a robotic action, and how that action's result would be reported somewhere a person could see it.",
    "Identify the single hardest integration challenge you expect to face — the point where two separately-working pieces might not connect smoothly — and describe how you would test for and debug that specific problem.",
    "Plan how you would present your finished project to someone unfamiliar with it: what problem would you explain first, what would you demonstrate live, and what would you honestly share about what you had to debug along the way."]}
 ],
 activity:"Write a one-page plan for your own capstone project: the real problem it solves, which modules from this course it combines, and how you would demonstrate it working to someone else.",
 check:[
  {q:"What is the main purpose of a capstone project, as described in this unit?",o:["To combine everything learned throughout a course into one coherent, working system","To repeat a single earlier module with no new integration","To avoid using any programming at all","To replace the need for a final exam with no other requirement"],a:0},
  {q:"Why is integration often described as harder than building any single piece alone?",o:["Small mismatches between separately-built components can cause the whole system to fail even when each part works individually","Integration requires no additional testing at all","Integration is only relevant to software, never to hardware","Integration always takes less time than building individual pieces"],a:0},
  {q:"What gave the winning student team's capstone project strong portfolio value?",o:["It was a working, demonstrable system that judges could see operate, not just a claim of having learned the material","It was the shortest project submitted","It avoided using any sensors or robotics","It relied entirely on a certificate with no working demonstration"],a:0}
 ]}
];

