  {q:"What did the church's chatbot do specifically when a user submitted a prayer request?",o:["It collected the prayer points with conversational structure, logged them safely, and escalated urgent cases to a live pastor","It deleted the message immediately with no response","It responded with an identical generic reply every time","It refused to accept any prayer requests through the chatbot"],a:0},
  {q:"What percentage of message traffic did the church's chatbot manage successfully, according to the story?",o:["90%","10%","100%, with zero human involvement at any point","50%, with the rest going completely unanswered"],a:0}
