// ── SUPABASE (Phase 1: auth + profiles) ─────────────────────────────────────
// Both values below are the client-side "anon"/"publishable" key and project
// URL — safe to be visible in the bundle. The real security boundary is the
// Row Level Security policies on the database, not secrecy of this key.
const SUPABASE_URL="https://jozqiwlqektnvsbaqayt.supabase.co";
const SUPABASE_ANON_KEY="sb_publishable_B_lgaTeYEp_xBDbWpSN4cg_kyQUUeHu";
// Explicit (rather than relying on defaults) so a browser refresh always
// restores the signed-in session from localStorage instead of dropping it.
const supabase=createClient(SUPABASE_URL, SUPABASE_ANON_KEY,{
  auth:{persistSession:true,autoRefreshToken:true,detectSessionInUrl:true},
});

// Maps a Supabase auth user + their `profiles` row into the flat user-object
// shape the rest of this app already expects (u.dob, u.guardianName, etc. as
// top-level fields) — so nothing else in the app needs to change for Phase 1.
function mapProfileToUser(authUser, row){
  const details=row?.details||{};
  return {
    id:authUser.id, email:authUser.email||row?.email||"",
    role:row?.role||"student", nick:row?.nick||"", name:row?.name||"",
    photo:row?.photo_url||null, refCode:row?.ref_code||null, regCode:row?.reg_code||null,
    referredBy:row?.referred_by||null, children:row?.children||[],
    xp:row?.xp??0, level:row?.level??1, streak:row?.streak??0,
    badges:row?.badges||[], subjects:row?.subjects||[],
    country:row?.country||"", currency:row?.currency||"USD", profession:row?.profession||"",
    payoutMethod:row?.payout_method||"", payoutBankName:row?.payout_bank_name||"",
    payoutAccountNumber:row?.payout_account_number||"", payoutAccountName:row?.payout_account_name||"",
    payoutMobileProvider:row?.payout_mobile_provider||"", payoutMobileNumber:row?.payout_mobile_number||"",
    ...details,
  };
}
// Same shape as mapProfileToUser, but for a bulk "give me every profile" query
// (the admin Users dashboard) where there's no individual authUser object to
// pull an id/email from — both come straight off the profiles row itself.
function mapProfileRowToUser(row){ return mapProfileToUser({id:row.id,email:row.email||""},row); }
async function fetchProfileRow(userId){
  const {data,error}=await supabase.from("profiles").select("*").eq("id",userId).single();
  if(error){ console.error("fetchProfileRow:",error.message); return null; }
  return data;
}

