  const [gfSubject,setGfSubject]=useState("");
  const [gfTerm,setGfTerm]=useState("Term 1");
  const [gfScores,setGfScores]=useState([{name:"",score:"",max:100,w:1}]);
  const [cfOpen,setCfOpen]=useState(false);
  const [cfId,setCfId]=useState(null);
  const [cfTeacher,setCfTeacher]=useState("");
  const [cfSubject,setCfSubject]=useState("");
  const [cfName,setCfName]=useState("");
  const [cfStudents,setCfStudents]=useState([]);
  const [ffOpen,setFfOpen]=useState(false);
  const [ffStudent,setFfStudent]=useState("");
  const [ffDesc,setFfDesc]=useState("");
  const [ffAmount,setFfAmount]=useState("");
  const [ffDue,setFfDue]=useState("");
